INSERT INTO `exams` VALUES ('1', '1', '矩阵乘法的基本规则是什么？', 'choice', 'B', '{\'A\': \'任意两个矩阵都可以相乘。\', \'B\': \'前一个矩阵的列数必须等于后一个矩阵的行数。\', \'C\': \'两个矩阵的行列数必须完全相同。\', \'D\': \'矩阵乘法与点乘完全一致。\'}', '5', '2025-06-08 22:24:51');
INSERT INTO `exams` VALUES ('2', '1', '如果矩阵A是3×2，矩阵B是2×4，那么它们的乘积结果矩阵C的维度是多少？', 'choice', 'C', '{\'A\': \'3×2\', \'B\': \'2×4\', \'C\': \'3×4\', \'D\': \'4×3\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('3', '1', '以下哪种方法可以用来实现矩阵乘法？', 'choice', 'D', '{\'A\': \'使用NumPy的dot函数。\', \'B\': \'直接用加法运算符。\', \'C\': \'使用字符串拼接。\', \'D\': \'通过手动嵌套循环计算每个元素值。\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('4', '1', '在Python中，如何定义一个二维数组（矩阵）？', 'choice', 'B', '{\'A\': \'使用花括号{}。\', \'B\': \'使用方括号[]嵌套表示。\', \'C\': \'使用圆括号()。\', \'D\': \'直接使用NumPy库初始化。\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('5', '1', '以下哪项描述了矩阵乘法的计算规则？', 'choice', 'C', '{\'A\': \'对应位置的元素直接相加。\', \'B\': \'对应位置的元素直接相减。\', \'C\': \'前一个矩阵的行元素与后一个矩阵的列元素分别相乘并求和。\', \'D\': \'所有元素统一相乘后再求和。\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('6', '1', '对于矩阵A(2×3)和矩阵B(3×4)，它们的乘积结果矩阵C有多少个元素？', 'choice', 'C', '{\'A\': \'6\', \'B\': \'8\', \'C\': \'12\', \'D\': \'24\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('7', '1', '在矩阵乘法中，如果矩阵A的维度为m×n，矩阵B的维度为n×p，则结果矩阵C的维度为？', 'choice', 'C', '{\'A\': \'m×n\', \'B\': \'n×p\', \'C\': \'m×p\', \'D\': \'p×m\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('8', '1', '以下哪种情况会导致矩阵乘法无法进行？', 'choice', 'A', '{\'A\': \'前一个矩阵的列数不等于后一个矩阵的行数。\', \'B\': \'两个矩阵的行列数完全相同。\', \'C\': \'两个矩阵都是方阵。\', \'D\': \'两个矩阵都是一维数组。\'}', '5', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('9', '1', '请简述矩阵乘法的计算步骤。', 'qa', '矩阵乘法的计算步骤为：1. 确保前一个矩阵的列数等于后一个矩阵的行数；2. 从前一个矩阵中取出一行，从后一个矩阵中取出一列；3. 将该行与该列对应位置的元素相乘并求和，得到结果矩阵的一个元素；4. 重复上述过程直到计算出所有元素。', null, '20', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('10', '1', '为什么矩阵乘法要求前一个矩阵的列数必须等于后一个矩阵的行数？', 'qa', '因为矩阵乘法的本质是将前一个矩阵的行向量与后一个矩阵的列向量进行内积运算，而内积运算的前提是两个向量的维度必须相同，因此要求前一个矩阵的列数等于后一个矩阵的行数。', null, '20', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('11', '1', '如果需要实现一个原生Python代码来完成矩阵乘法，请简述其实现思路。', 'qa', '实现思路为：1. 遍历前一个矩阵的每一行；2. 对于每一行，遍历后一个矩阵的每一列；3. 计算当前行与当前列的内积（即对应位置元素相乘并求和），并将结果存入结果矩阵的相应位置；4. 最终返回结果矩阵。', null, '20', '2025-06-08 22:24:53');
INSERT INTO `exams` VALUES ('12', '2', '以下哪一项是向量数据库Chroma的主要应用场景？', 'choice', 'B', '{\'A\': \'通用搜索引擎优化\', \'B\': \'在线智能客服\', \'C\': \'实时数据流处理\', \'D\': \'大规模图像分类\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('13', '2', '在神经网络中，用于生成向量的模型可以被称为：', 'choice', 'A', '{\'A\': \'磁迁入模型\', \'B\': \'卷积神经网络\', \'C\': \'循环神经网络\', \'D\': \'支持向量机\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('14', '2', '关于Chroma数据库的应用，以下哪项描述正确？', 'choice', 'C', '{\'A\': \'主要用于通用问答任务\', \'B\': \'仅支持文本数据的存储\', \'C\': \'适用于特定领域知识的问答系统\', \'D\': \'不支持与前后端交互\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('15', '2', '以下哪个模型可以用于生成高质量的文本嵌入向量？', 'choice', 'A', '{\'A\': \'BERT\', \'B\': \'ResNet\', \'C\': \'YOLO\', \'D\': \'VGG16\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('16', '2', 'Olama embedding使用的具体模型版本为：', 'choice', 'B', '{\'A\': \'7B\', \'B\': \'2.5B\', \'C\': \'10B\', \'D\': \'1.5B\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('17', '2', '以下哪一项不是质朴AI提供的功能？', 'choice', 'D', '{\'A\': \'文本生成\', \'B\': \'多模态视觉识别\', \'C\': \'文生图\', \'D\': \'硬件加速计算\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('18', '2', '通议千问支持哪些调用方式？（多选）', 'choice', 'ABC', '{\'A\': \'SDK (Python)\', \'B\': \'SDK (Java)\', \'C\': \'HTTP协议调用\', \'D\': \'命令行工具\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('19', '2', '以下哪一项是质朴AI的优点？', 'choice', 'B', '{\'A\': \'接口复杂但功能强大\', \'B\': \'价格低廉且接口简单\', \'C\': \'仅支持单一模型\', \'D\': \'不支持多模态任务\'}', '5', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('20', '2', '请简述向量数据库Chroma的核心功能及其应用场景。', 'qa', '向量数据库Chroma的核心功能是将知识或文档转化为向量进行存储和检索。其主要应用场景包括在线智能客服、特定领域的问答系统等，能够针对企业或组织的专有知识提供高效的查询服务。', null, '20', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('21', '2', '什么是磁迁入模型？它在自然语言处理中的作用是什么？', 'qa', '磁迁入模型是一种用于生成文本嵌入向量的深度学习模型。在自然语言处理中，它的作用是将文本转化为高维向量表示，从而捕捉语义信息，为后续任务（如分类、检索、生成等）提供基础数据支持。', null, '20', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('22', '2', '对比通议千问和质朴AI，分析它们各自的优缺点。', 'qa', '通议千问的优点是支持多种模型和任务，功能全面；缺点是接口相对复杂。质朴AI的优点是价格低廉、接口简单，同时支持多模态任务；缺点是功能可能不如通议千问丰富。根据实际需求选择合适的工具更为重要。', null, '20', '2025-06-08 22:25:32');
INSERT INTO `exams` VALUES ('23', '3', '位置编码中，假设pos为01、11、21、31时，这些位置对应的向量是否相同？', 'choice', 'A', '{\'A\': \'完全相同\', \'B\': \'部分相同\', \'C\': \'完全不同\', \'D\': \'无法判断\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('24', '3', '在位置编码公式中，分母的值由什么决定？', 'choice', 'B', '{\'A\': \'pos的值\', \'B\': \'d_model的值\', \'C\': \'i的值\', \'D\': \'以上都不对\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('25', '3', '为什么通常将位置编码中的基数取为10000？', 'choice', 'B', '{\'A\': \'方便计算\', \'B\': \'经验值表明效果较好\', \'C\': \'便于存储\', \'D\': \'随机选择\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('26', '3', '位置编码中，当i等于d/2时，指数的最大值是多少？', 'choice', 'A', '{\'A\': \'1\', \'B\': \'d\', \'C\': \'d/2\', \'D\': \'2i\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('27', '3', '位置编码公式的分子部分是什么？', 'choice', 'C', '{\'A\': \'pos\', \'B\': \'10000^(2i/d)\', \'C\': \'pos * 10000^(2i/d)\', \'D\': \'pos / 10000^(2i/d)\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('28', '3', '在位置编码中，如何通过公式确定不同词的位置关系？', 'choice', 'A', '{\'A\': \'通过距离的线性相关性\', \'B\': \'通过向量的模长\', \'C\': \'通过角度的余弦值\', \'D\': \'通过位置索引的绝对值\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('29', '3', '在位置编码中，若i固定，随着pos增加，向量的变化规律是？', 'choice', 'C', '{\'A\': \'呈等差数列变化\', \'B\': \'呈等比数列变化\', \'C\': \'呈线性相关变化\', \'D\': \'无规律变化\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('30', '3', '在位置编码中，若i=0，则分子的最大值是多少？', 'choice', 'A', '{\'A\': \'1\', \'B\': \'0.0001\', \'C\': \'10000\', \'D\': \'d_model\'}', '5', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('31', '3', '解释一下为什么位置编码可以表示词语之间的相对位置关系？', 'qa', '位置编码通过引入sin和cos函数，使得不同位置的编码具有周期性和相对性，从而能够反映词语之间的相对位置关系。例如，通过公式计算，即使位置发生变化，其相对关系仍可以通过编码体现出来。', null, '20', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('32', '3', '请说明位置编码中10000^(2i/d)的作用及其意义。', 'qa', '10000^(2i/d)用于控制位置编码的变化范围，确保不同维度上的变化幅度适中。它使得低频位置信息（较大的i）变化较慢，而高频位置信息（较小的i）变化较快，从而更好地捕捉词语之间的相对位置关系。', null, '20', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('33', '3', '如何通过位置编码公式验证两个词的位置是否线性相关？', 'qa', '通过位置编码公式，我们可以观察到同一维度下，随着位置索引pos的变化，向量值呈现线性递增或递减的关系。因此，如果两个词的位置编码在某些维度上满足这种线性递增或递减关系，则可以认为它们的位置是线性相关的。', null, '20', '2025-06-08 22:26:02');
INSERT INTO `exams` VALUES ('34', '4', '最小二乘法主要用于解决以下哪种问题？', 'choice', 'B', '{\'A\': \'分类问题\', \'B\': \'回归问题\', \'C\': \'聚类问题\', \'D\': \'降维问题\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('35', '4', '在一元线性回归中，我们通过最小二乘法主要求解的是哪两个参数？', 'choice', 'A', '{\'A\': \'a和b\', \'B\': \'x和y\', \'C\': \'σ和μ\', \'D\': \'w和b\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('36', '4', '在机器学习中，预测的主要目的是什么？', 'choice', 'A', '{\'A\': \'从历史数据中提取规律并进行未来推断\', \'B\': \'仅对已有数据进行分类\', \'C\': \'生成新的数据\', \'D\': \'单纯优化计算效率\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('37', '4', '鸡兔同笼问题可以通过哪种方法求解？（多选）', 'choice', 'AB', '{\'A\': \'数学公式法\', \'B\': \'穷举法\', \'C\': \'机器学习模型\', \'D\': \'深度神经网络\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('38', '4', '多元线性回归相较于一元线性回归的区别在于：', 'choice', 'B', '{\'A\': \'只有一个自变量\', \'B\': \'有多个自变量\', \'C\': \'无法使用最小二乘法\', \'D\': \'必须使用神经网络求解\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('39', '4', '以下哪个领域可以被归结为预测问题？', 'choice', 'D', '{\'A\': \'图像识别\', \'B\': \'文本分类\', \'C\': \'用户行为分析\', \'D\': \'以上全部\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('40', '4', '在鸡兔同笼问题中，若头数为35，脚数为94，则兔子的数量是多少？', 'choice', 'B', '{\'A\': \'12\', \'B\': \'23\', \'C\': \'35\', \'D\': \'94\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('41', '4', '机器学习中的函数拟合与传统数学方法相比，优势在于：', 'choice', 'A', '{\'A\': \'更适合处理复杂的非线性关系\', \'B\': \'计算速度更快\', \'C\': \'完全不需要人工干预\', \'D\': \'无需数据即可完成预测\'}', '5', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('42', '4', '请简述最小二乘法的基本原理及其应用场景。', 'qa', '最小二乘法是一种用于寻找最佳拟合直线或曲线的方法，其基本原理是通过最小化误差的平方和来确定模型参数。它广泛应用于回归分析中，用于预测连续型变量的值。例如，在一元线性回归中，我们通过最小二乘法求解斜率和截距，从而得到最佳拟合直线。', null, '20', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('43', '4', '在实际应用中，如何判断一个问题是适合用机器学习方法还是传统数学方法解决？', 'qa', '如果问题是简单的线性关系或已知明确的数学公式，则传统数学方法更为高效；但如果问题涉及复杂的非线性关系、高维数据或大量未知参数，则机器学习方法更具优势。此外，当数据量较大且需要自动化处理时，机器学习也更适用。', null, '20', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('44', '4', '结合鸡兔同笼问题，说明数学公式法和机器学习方法在解决问题时的异同点。', 'qa', '数学公式法直接利用已知条件建立方程组并求解，过程清晰且结果精确；而机器学习方法则可能通过训练模型（如回归模型）来拟合输入输出关系，虽然也能得出正确答案，但通常需要更多数据和计算资源。两者的主要区别在于，数学公式法依赖于明确的规则，而机器学习方法更注重从数据中自动学习规律。', null, '20', '2025-06-08 22:26:51');
INSERT INTO `exams` VALUES ('45', '5', '在图像处理中，使用NumPy数组表示图像时，如何实现图像的旋转？', 'choice', 'B', '{\'A\': \'通过改变数组的形状（shape）\', \'B\': \'通过调用NumPy内置的rotate函数\', \'C\': \'通过调整数组的索引顺序\', \'D\': \'直接修改数组中的像素值\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('46', '5', '如果要将一张图像逆时针旋转90度，以下哪个选项是正确的操作方法？', 'choice', 'C', '{\'A\': \'rotate(image, 90)\', \'B\': \'rotate(image, -90)\', \'C\': \'rotate(image, 270)\', \'D\': \'rotate(image, k=3)\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('47', '5', 'NumPy中的`np.rot90`函数默认参数k=1时，表示图像如何旋转？', 'choice', 'B', '{\'A\': \'顺时针旋转90度\', \'B\': \'逆时针旋转90度\', \'C\': \'顺时针旋转270度\', \'D\': \'不旋转\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('48', '5', '在图像处理中，旋转图像的本质是什么？', 'choice', 'B', '{\'A\': \'改变图像的颜色通道\', \'B\': \'改变图像像素点的排列方式\', \'C\': \'增加或减少图像的分辨率\', \'D\': \'压缩或拉伸图像的尺寸\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('49', '5', '如果需要将图像顺时针旋转270度，等价于以下哪种操作？', 'choice', 'A', '{\'A\': \'逆时针旋转90度\', \'B\': \'逆时针旋转180度\', \'C\': \'顺时针旋转90度\', \'D\': \'逆时针旋转270度\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('50', '5', '在NumPy中，执行`np.rot90(image, k=2)`后，图像会发生什么变化？', 'choice', 'A', '{\'A\': \'顺时针旋转180度\', \'B\': \'逆时针旋转180度\', \'C\': \'顺时针旋转90度\', \'D\': \'逆时针旋转90度\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('51', '5', '假设图像的高度为H，宽度为W，旋转90度后，新的高度和宽度分别是多少？', 'choice', 'B', '{\'A\': \'高度仍为H，宽度仍为W\', \'B\': \'高度为W，宽度为H\', \'C\': \'高度为H/2，宽度为W/2\', \'D\': \'高度为2H，宽度为2W\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('52', '5', '在NumPy中，`np.rot90`函数的参数k表示什么？', 'choice', 'C', '{\'A\': \'旋转的角度\', \'B\': \'旋转的方向\', \'C\': \'旋转的次数\', \'D\': \'旋转的速度\'}', '5', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('53', '5', '请解释图像旋转过程中，为什么需要调整像素点的排列顺序？', 'qa', '图像旋转的本质是对像素点重新排列。当图像被旋转时，原始像素点的位置会发生变化，因此需要根据旋转角度重新计算每个像素点的新位置，从而生成旋转后的图像。', null, '20', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('54', '5', '在NumPy中，如何实现图像的顺时针旋转90度？请写出具体的操作步骤。', 'qa', '在NumPy中，可以通过`np.rot90(image, k=-1)`实现图像的顺时针旋转90度。其中，参数`k=-1`表示顺时针旋转一次（即90度）。', null, '20', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('55', '5', '如果需要将一张图像先顺时针旋转90度，再逆时针旋转90度，最终图像会有什么变化？', 'qa', '最终图像将恢复到原始状态。因为顺时针旋转90度相当于逆时针旋转270度，而逆时针旋转90度恰好抵消了之前的旋转操作，因此图像回到初始状态。', null, '20', '2025-06-08 22:27:36');
INSERT INTO `exams` VALUES ('56', '6', '向量数据库Chroma的主要应用场景是什么？', 'choice', 'B', '{\'A\': \'通用问答系统\', \'B\': \'在线智能客服\', \'C\': \'图像识别\', \'D\': \'语音合成\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('57', '6', '在向量化过程中，以下哪种模型可以用于生成向量？', 'choice', 'D', '{\'A\': \'BERT\', \'B\': \'GPT\', \'C\': \'OpenAI Embedding\', \'D\': \'以上皆可\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('58', '6', '以下哪项不是质朴AI（Zhipu AI）提供的功能？', 'choice', 'D', '{\'A\': \'文本生成\', \'B\': \'多模态视觉识别\', \'C\': \'文生图\', \'D\': \'硬件加速\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('59', '6', '关于Olama Embedding模型，以下描述正确的是？', 'choice', 'B', '{\'A\': \'只能用于英文文本\', \'B\': \'基于千万2.5.7B模型训练\', \'C\': \'不支持API调用\', \'D\': \'无法用于在线客服\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('60', '6', '通义千问（Qwen）和质朴AI相比，以下哪项是正确的？', 'choice', 'C', '{\'A\': \'通义千问价格更便宜\', \'B\': \'质朴AI接口更复杂\', \'C\': \'两者都支持HTTP协议调用\', \'D\': \'质朴AI不支持Python SDK\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('61', '6', 'CogView和CogVideo分别对应的功能是？', 'choice', 'B', '{\'A\': \'文本生成和语音合成\', \'B\': \'文生图和文生视频\', \'C\': \'图像识别和语音识别\', \'D\': \'自然语言处理和机器翻译\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('62', '6', '以下哪种方式不能用于调用质朴AI的服务？', 'choice', 'D', '{\'A\': \'Python SDK\', \'B\': \'Java SDK\', \'C\': \'HTTP请求\', \'D\': \'直接编译源码\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('63', '6', '在神经网络中，每一层模型都可以单独拼接出来，这种说法是否正确？', 'choice', 'A', '{\'A\': \'正确\', \'B\': \'错误\', \'C\': \'视情况而定\', \'D\': \'无法判断\'}', '5', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('64', '6', '向量数据库Chroma的核心作用是什么？请简要说明。', 'qa', '向量数据库Chroma的核心作用是将知识或文档进行向量化存储，并通过相似度搜索实现高效的知识检索。这对于构建在线智能客服等场景非常关键。', null, '20', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('65', '6', '质朴AI（Zhipu AI）有哪些优势？请列举至少两点。', 'qa', '1. 提供多种能力，包括文本生成、多模态视觉识别和文生图；2. 接口简单且支持多种编程语言（如Python、Java）及HTTP协议调用；3. 价格相对较低，适合实验和小规模应用。', null, '20', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('66', '6', '如何利用Chroma和LongChain构建一个在线智能客服系统？请简述步骤。', 'qa', '1. 使用Chroma加载并向量化企业专属文档或知识库；2. 利用LongChain框架整合向量数据库与大语言模型（如通义千问）；3. 开发前后端交互界面，允许用户输入问题并获取智能回答；4. 部署系统并优化性能以适应实际需求。', null, '20', '2025-06-08 22:28:17');
INSERT INTO `exams` VALUES ('67', '7', '神经网络中最核心的组成部分是什么？', 'choice', 'B', '{\'A\': \'激活函数\', \'B\': \'神经元\', \'C\': \'权重\', \'D\': \'连接线\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('68', '7', '在神经网络中，连接的作用是什么？', 'choice', 'A', '{\'A\': \'传递信号\', \'B\': \'存储数据\', \'C\': \'定义模型结构\', \'D\': \'调整参数\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('69', '7', '激活函数的主要作用是什么？', 'choice', 'A', '{\'A\': \'增加模型的非线性能力\', \'B\': \'减少模型参数\', \'C\': \'加速训练过程\', \'D\': \'优化网络结构\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('70', '7', '全连接层的特点是什么？', 'choice', 'B', '{\'A\': \'每个神经元只与部分神经元相连\', \'B\': \'每个神经元都与其他神经元相连\', \'C\': \'只有输入层和输出层相连\', \'D\': \'只有隐藏层之间相连\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('71', '7', '以下哪种情况会导致神经网络模型的泛化能力降低？', 'choice', 'C', '{\'A\': \'使用了过多的激活函数\', \'B\': \'网络层数过深\', \'C\': \'参数全部为线性变化\', \'D\': \'输入数据过于复杂\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('72', '7', '激活函数如何帮助神经网络进行参数取舍？', 'choice', 'B', '{\'A\': \'通过将所有参数设置为零\', \'B\': \'通过将部分参数值变为零或无效\', \'C\': \'通过增加更多的神经元\', \'D\': \'通过减少网络层数\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('73', '7', '以下哪一项不是激活函数的作用？', 'choice', 'C', '{\'A\': \'引入非线性变化\', \'B\': \'过滤无用参数\', \'C\': \'直接优化权重值\', \'D\': \'控制参数传播\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('74', '7', '为什么神经网络需要模仿人脑神经元？', 'choice', 'C', '{\'A\': \'为了完全复制人脑功能\', \'B\': \'为了提高计算效率\', \'C\': \'为了实现更复杂的任务处理\', \'D\': \'为了简化模型结构\'}', '5', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('75', '7', '请解释什么是全连接层，并举例说明其工作原理。', 'qa', '全连接层是指神经网络中每一层的神经元都与下一层的所有神经元相连。例如，如果有5个神经元连接到下一层的6个神经元，则会有30条连接线。这些连接线上的权重决定了信息传递的方式。', null, '20', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('76', '7', '激活函数在神经网络中的具体作用是什么？请结合实际应用场景说明。', 'qa', '激活函数用于对神经元的输入进行非线性变化，从而增强模型的表达能力和泛化能力。例如，在图像分类任务中，激活函数可以过滤掉无关特征，突出关键信息，帮助模型更好地识别目标。', null, '20', '2025-06-08 23:59:23');
INSERT INTO `exams` VALUES ('77', '7', '为什么神经网络需要避免参数的线性变化？请结合理论和实际应用进行分析。', 'qa', '如果参数仅发生线性变化，神经网络的每一层相当于只是简单地叠加线性变换，最终模型等价于单层线性模型，无法处理复杂的非线性问题。例如，在语音识别任务中，线性模型难以捕捉音频信号中的复杂模式，而引入非线性激活函数后，模型性能显著提升。', null, '20', '2025-06-08 23:59:23');
