INSERT INTO `videos` VALUES ('1', '矩阵乘法运算规则', '20250606_214509_089650.mp4', '527', '机器学习', '我们来看一看啊 关于这个矩阵乘法这也是我们科学运算里边啊大批量数据处理的时候也经常用到的一种算法啊这一种惩罚方式呢它呢 针对的是两个矩阵 也就是二维数组了 对吧二维数组就是一个矩阵嘛 对不对就是一个二维数组针对这个二维数组那么矩正乘法这个就是我们矩正里边的一种很特殊的情况那么矩正比方说这是A大A这是一个矩正这个矩正对应的是不是一个三行两列你用二位书主表示就是一个是不是三行两列B呢是一个两行一列对吧两行一列好那么最后这个矩正乘法算出来的结果是什么呢注意算出来的结果是三行一列这里面就以据乘乘法就有一个要求M行N列只能和N行P列这个列前一个矩阵的列和后一个矩阵的行必须是一样大的比方说我有一个矩阵是三行四列那我要乘的另外一个矩阵它必须是四行它必须是四行多少列无所谓三列也行四列也行五列也行那最后这两个矩阵乘法乘出来的结果是多少三行五列这个怎么算的来我们来看一看这边算法是这样的算法是这样的比方说A11 A12这是不是一个三行两列加上两行一列他们的算法就是A11乘以B11加上A12乘以B21是这样来算的这个和这个这个和这个算出来的结果等于什么等于他们的第一个值好这一行呢又和这个这个A2又和B21算出来的结果呢又等于这个这个和它相乘然后这个呢又和它相乘算出来结果等于第三个那你自己先看一看那么也就是说针对M乘以N的一个矩阵和N乘一个P的矩阵他们俩才能正常的做矩阵乘法注意这根点击啊点乘是不一样的矩正存法那这是三行两列那这边两行四列运算出来的结果就是三行四列它怎么算的来我给大家看看19是怎么算的两行三列三行两列嘛那就1乘以那个1乘以3得到的是3完了以后加上3乘以2得到了16那就得到第一个值9这是不是还有几列刚才这个是一列嘛这边是四列了那就继续写一下1和33和2得到一个什么9然后接下来又1和63和73和7得到27接下来是1和93和83和824得到33接下来是1乘以43乘以3等于13好 接下来又开始第二行第二行是什么那就5乘以3加上2乘以2等于什么19然后5乘以7加上不是7加乘以65乘以6加上2乘以72714575630444明白这意思了吗这样呢就是我们的矩阵乘法的运算规则好现在呢我来给大家稍微的定义这么两个矩阵n d 1等于 np 点 array二维的 1234或者我们就用这个好了135204好135250 4 是不是定义了一个三行两类N第二呢 我就定义两行四两五六来的四列 那就36943694 在第一行对吧 第二行2783那么我们来看看NP.DOTND1ND2他们的矩正乘法乘出来的结果是不是这个数92733131944是不是这个数OK这个叫矩正乘法对应简单来说就是对应位置的行和对应位置的列相乘最终M乘N乘以N乘P得到的是M乘P的这么一个新的矩阵新的矩阵这个呢跟我们的卷积那种还有点像有点那个意思但是算法不一样对吧有点那个意思这个叫矩阵存法它可以让我们呢比较方便的对这些数据进行一个快速的批量的运算比较简洁调用一个dota就搞定了好这就是矩正惩罚有没有问题No.py里边内置的没有问题的话那我现在就要出今天的第一个作业利用原生python代码对两个二维列表进行矩正乘法运算进行一个不能使用任何第三方库包括number five只能有最原始的对两个二维列表我这边是不是定义的就是两个列表对吧两个列表但这个列表要通用啊然后呢对进行然后包封装到封装到这个方法函数函数metrics中然后里面的参数传的是什么list1 list2list1返回矩正乘法的结果返回矩正存法的结果 能听懂这个题目的要求吗啊 然后就是说呢我们使用最原始的方法 你们来用python手算一下啊 还是那种今天呢 还是让大家就是用比较纯粹的方式 但我给他讲了一些python化的编程方式哈 你能利用尽量利用 但是你不能使用第三方库啊 你说我直接调一下np点dota完事啊老师这个什么这个作业啊我们使用原生的当然明白这个意思啊自己去循环去算乘法再算加法再把它合并成一个什么新的二维数组新的二维数组好吧这是我们今天的第一个作业那么number pi呢我就先给大家去讲到这了其他的一些操作后边我们还会经常使用但基本操作我们都给大家讲过了你那明天就稍微的把这些操作快速的放几个列表出来念一念有点概念就行了然后后边用到的时候大家就这个正常用正常去使用它好吧这就是关于number pi的部分就给大家去梳理到这里就可以了我们学会我今天讲的这些number pi的基本操作就OK了不需要再去学别的了', '<h2>课程笔记：矩阵乘法及其Python实现</h2>\n\n<p>本节课主要讲解了矩阵乘法的基本概念、运算规则以及如何通过原生Python代码实现矩阵乘法。</p>\n\n<h3>一、矩阵乘法的概念</h3>\n<ul>\n    <li>矩阵乘法是科学计算中常用的算法，尤其在大批量数据处理时非常重要。</li>\n    <li>矩阵乘法适用于两个二维数组（矩阵），假设矩阵A为M行N列，矩阵B为N行P列，则它们的乘积结果为一个M行P列的矩阵。</li>\n    <li>矩阵乘法的条件：前一个矩阵的列数必须等于后一个矩阵的行数。</li>\n</ul>\n\n<h3>二、矩阵乘法的运算规则</h3>\n<ul>\n    <li>结果矩阵中的每个元素是由第一个矩阵的某一行与第二个矩阵的某一列对应元素相乘后再求和得到。</li>\n    <li>例如：\n        <pre>\n            A = [[a11, a12], [a21, a22]]\n            B = [[b11], [b21]]\n            结果 C = [[a11*b11 + a12*b21], [a21*b11 + a22*b21]]\n        </pre>\n    </li>\n</ul>\n\n<h3>三、示例</h3>\n<ul>\n    <li>假设矩阵A为[[1, 3], [5, 2]]，矩阵B为[[3, 6, 9, 4], [2, 7, 8, 3]]。</li>\n    <li>按照矩阵乘法规则，结果矩阵C为[[9, 27, 33, 13], [19, 44, 53, 29]]。</li>\n</ul>\n\n<h3>四、Python实现矩阵乘法</h3>\n<ul>\n    <li>作业要求：使用原生Python代码实现矩阵乘法，不能使用任何第三方库（如NumPy）。</li>\n    <li>具体步骤：\n        <ol>\n            <li>定义两个二维列表作为输入矩阵。</li>\n            <li>编写一个函数`metrics`，接收两个参数`list1`和`list2`，分别表示两个矩阵。</li>\n            <li>在函数内部，通过嵌套循环实现矩阵乘法运算。</li>\n            <li>返回结果矩阵。</li>\n        </ol>\n    </li>\n    <li>代码框架示例：\n        <pre>\ndef metrics(list1, list2):\n    # 检查矩阵是否可以相乘\n    if len(list1[0]) != len(list2):\n        return \"无法进行矩阵乘法\"\n\n    # 初始化结果矩阵\n    result = []\n    for i in range(len(list1)):\n        row = []\n        for j in range(len(list2[0])):\n            sum_product = 0\n            for k in range(len(list2)):\n                sum_product += list1[i][k] * list2[k][j]\n            row.append(sum_product)\n        result.append(row)\n    return result\n\n# 示例调用\nlist1 = [[1, 3], [5, 2]]\nlist2 = [[3, 6, 9, 4], [2, 7, 8, 3]]\nprint(metrics(list1, list2))\n        </pre>\n    </li>\n</ul>\n\n<h3>五、总结</h3>\n<ul>\n    <li>矩阵乘法是一种重要的数学运算，广泛应用于科学计算和数据分析。</li>\n    <li>掌握矩阵乘法的规则，并能够通过原生Python代码实现，有助于加深对矩阵运算的理解。</li>\n    <li>今天的作业旨在让大家通过手动实现矩阵乘法，进一步熟悉Python编程的基础知识。</li>\n</ul>', '矩阵乘法', '[{\'link\': \'https://m.thepaper.cn/newsDetail_forward_29358046\', \'title\': \'矩阵乘法为什么是这样定义的？\', \'content\': \'矩阵乘法为什么是这样定义的？\\n...次乘积之和。矩阵乘法的定义必须由复合线性算子的观点来理解：线性算子T:Rn →Rm由矩阵A确定，复合算子S∘T对应的矩阵C=AB，其中A是S的矩阵表示，B是T的矩阵表示。\', \'snippet\': \'...次乘积之和。矩阵乘法的定义必须由复合线性算子的观点来理解：线性算子T:Rn →Rm由矩阵A确定，复合算子S∘T对应的矩阵C=AB，其中A是S的矩阵表示，B是T的矩阵表示。\', \'position\': None}, {\'link\': \'http://m.gaosan.com/gaokao/573302.html\', \'title\': \'矩阵的乘法运算法则\', \'content\': \'矩阵的乘法运算法则\\n矩阵的乘法运算法则有：乘法结合律：（AB）C=A（BC）；乘法左分配律：（A+B）C=AC+BC；乘法右分配律：C（A+B）=CA+CB；对数乘的结合性k（AB）=（kA）B=A（kB）。\', \'snippet\': \'矩阵的乘法运算法则有：乘法结合律：（AB）C=A（BC）；乘法左分配律：（A+B）C=AC+BC；乘法右分配律：C（A+B）=CA+CB；对数乘的结合性k（AB）=（kA）B=A（kB）。\', \'position\': None}, {\'link\': \'https://geek-docs.com/linear-algebra/matrix/matrix-multiplication.html\', \'title\': \'矩阵乘法\', \'content\': \'矩阵乘法\\n英语：matrix multiplication）是一种根据两个矩阵得到第三个矩阵的二元运算，第三个矩阵即前两者的乘积，称为矩阵积（英语：matrix product）。设$$A$$是$${\\\\displaystyle n\\\\times m}$$的矩阵，$$B$$是$$m\\\\times p$$的矩阵，则它们的矩阵积$$AB$$是$$n\\\\times p$$的矩阵。$$A$$...\', \'snippet\': \'英语：matrix multiplication）是一种根据两个矩阵得到第三个矩阵的二元运算，第三个矩阵即前两者的乘积，称为矩阵积（英语：matrix product）。设$$A$$是$${\\\\displaystyle n\\\\times m}$$的矩阵，$$B$$是$$m\\\\times p$$的矩阵，则它们的矩阵积$$AB$$是$$n\\\\times p$$的矩阵。$$A$$...\', \'position\': None}, {\'link\': \'https://m.thepaper.cn/newsDetail_forward_29358046\', \'title\': \'矩阵乘法为什么是这样定义的？\', \'content\': \'矩阵乘法为什么是这样定义的？\\nm行k列矩阵A和k行n列矩阵B的乘积矩阵AB是一个m行n列矩阵C，其位于第i行和第j列的元素Cij是矩阵A第i行的总共k个元素和矩阵B第j列的总共k个元素的一对一依次乘积之和。 有没有想过，为什么要这样定义呢？ 许多线性代数教材着眼于“算”，却鲜少对图景的整体把握。死记硬背之下，不少学生知其然而不知其所以然。本文试图从线性算子的复合，自然引出矩阵乘法规则。如果你能耐心读到最后，定会豁...\', \'snippet\': \'m行k列矩阵A和k行n列矩阵B的乘积矩阵AB是一个m行n列矩阵C，其位于第i行和第j列的元素Cij是矩阵A第i行的总共k个元素和矩阵B第j列的总共k个元素的一对一依次乘积之和。 有没有想过，为什么要这样定义呢？ 许多线性代数教材着眼于“算”，却鲜少对图景的整体把握。死记硬背之下，不少学生知其然而不知其所以然。本文试图从线性算子的复合，自然引出矩阵乘法规则。如果你能耐心读到最后，定会豁...\', \'position\': None}]', '\n{\n  \"meta\": {\n    \"name\": \"矩阵乘法\",\n    \"author\": \"AI生成\",\n    \"version\": \"1.0\"\n  },\n  \"format\": \"node_tree\",\n  \"data\": {\n    \"id\": \"1\",\n    \"topic\": \"矩阵乘法与NumPy基础\",\n    \"children\": [\n      {\n        \"id\": \"1-1\",\n        \"topic\": \"矩阵乘法的基本概念\",\n        \"children\": [\n          {\n            \"id\": \"1-1-1\",\n            \"topic\": \"定义：MxN矩阵与NxP矩阵相乘得到MxP矩阵\"\n          },\n          {\n            \"id\": \"1-1-2\",\n            \"topic\": \"规则：前矩阵的列数必须等于后矩阵的行数\"\n          },\n          {\n            \"id\": \"1-1-3\",\n            \"topic\": \"计算方法：对应行与列元素相乘并求和\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-2\",\n        \"topic\": \"矩阵乘法示例\",\n        \"children\": [\n          {\n            \"id\": \"1-2-1\",\n            \"topic\": \"示例1：三行两列与两行四列矩阵相乘\"\n          },\n          {\n            \"id\": \"1-2-2\",\n            \"topic\": \"结果：三行四列矩阵\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-3\",\n        \"topic\": \"NumPy中的矩阵乘法\",\n        \"children\": [\n          {\n            \"id\": \"1-3-1\",\n            \"topic\": \"使用np.array定义矩阵\"\n          },\n          {\n            \"id\": \"1-3-2\",\n            \"topic\": \"使用np.dot实现矩阵乘法\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-4\",\n        \"topic\": \"作业要求\",\n        \"children\": [\n          {\n            \"id\": \"1-4-1\",\n            \"topic\": \"使用原生Python实现矩阵乘法\"\n          },\n          {\n            \"id\": \"1-4-2\",\n            \"topic\": \"输入：两个二维列表\"\n          },\n          {\n            \"id\": \"1-4-3\",\n            \"topic\": \"输出：返回矩阵乘法结果（二维列表）\"\n          },\n          {\n            \"id\": \"1-4-4\",\n            \"topic\": \"限制：不能使用第三方库，包括NumPy\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-5\",\n        \"topic\": \"总结\",\n        \"children\": [\n          {\n            \"id\": \"1-5-1\",\n            \"topic\": \"矩阵乘法是科学计算中的重要工具\"\n          },\n          {\n            \"id\": \"1-5-2\",\n            \"topic\": \"NumPy简化了矩阵运算过程\"\n          },\n          {\n            \"id\": \"1-5-3\",\n            \"topic\": \"掌握基本操作即可满足大部分需求\"\n          }\n        ]\n      }\n    ]\n  }\n}\n', '\n{\n    \"choices\": [\n        {\n            \"question\": \"矩阵乘法的基本规则是什么？\",\n            \"options\": {\n                \"A\": \"任意两个矩阵都可以相乘。\",\n                \"B\": \"前一个矩阵的列数必须等于后一个矩阵的行数。\",\n                \"C\": \"两个矩阵的行列数必须完全相同。\",\n                \"D\": \"矩阵乘法与点乘完全一致。\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"如果矩阵A是3×2，矩阵B是2×4，那么它们的乘积结果矩阵C的维度是多少？\",\n            \"options\": {\n                \"A\": \"3×2\",\n                \"B\": \"2×4\",\n                \"C\": \"3×4\",\n                \"D\": \"4×3\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"以下哪种方法可以用来实现矩阵乘法？\",\n            \"options\": {\n                \"A\": \"使用NumPy的dot函数。\",\n                \"B\": \"直接用加法运算符。\",\n                \"C\": \"使用字符串拼接。\",\n                \"D\": \"通过手动嵌套循环计算每个元素值。\"\n            },\n            \"answer\": \"D\"\n        },\n        {\n            \"question\": \"在Python中，如何定义一个二维数组（矩阵）？\",\n            \"options\": {\n                \"A\": \"使用花括号{}。\",\n                \"B\": \"使用方括号[]嵌套表示。\",\n                \"C\": \"使用圆括号()。\",\n                \"D\": \"直接使用NumPy库初始化。\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"以下哪项描述了矩阵乘法的计算规则？\",\n            \"options\": {\n                \"A\": \"对应位置的元素直接相加。\",\n                \"B\": \"对应位置的元素直接相减。\",\n                \"C\": \"前一个矩阵的行元素与后一个矩阵的列元素分别相乘并求和。\",\n                \"D\": \"所有元素统一相乘后再求和。\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"对于矩阵A(2×3)和矩阵B(3×4)，它们的乘积结果矩阵C有多少个元素？\",\n            \"options\": {\n                \"A\": \"6\",\n                \"B\": \"8\",\n                \"C\": \"12\",\n                \"D\": \"24\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"在矩阵乘法中，如果矩阵A的维度为m×n，矩阵B的维度为n×p，则结果矩阵C的维度为？\",\n            \"options\": {\n                \"A\": \"m×n\",\n                \"B\": \"n×p\",\n                \"C\": \"m×p\",\n                \"D\": \"p×m\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"以下哪种情况会导致矩阵乘法无法进行？\",\n            \"options\": {\n                \"A\": \"前一个矩阵的列数不等于后一个矩阵的行数。\",\n                \"B\": \"两个矩阵的行列数完全相同。\",\n                \"C\": \"两个矩阵都是方阵。\",\n                \"D\": \"两个矩阵都是一维数组。\"\n            },\n            \"answer\": \"A\"\n        }\n    ],\n    \"qas\": [\n        {\n            \"question\": \"请简述矩阵乘法的计算步骤。\",\n            \"answer\": \"矩阵乘法的计算步骤为：1. 确保前一个矩阵的列数等于后一个矩阵的行数；2. 从前一个矩阵中取出一行，从后一个矩阵中取出一列；3. 将该行与该列对应位置的元素相乘并求和，得到结果矩阵的一个元素；4. 重复上述过程直到计算出所有元素。\"\n        },\n        {\n            \"question\": \"为什么矩阵乘法要求前一个矩阵的列数必须等于后一个矩阵的行数？\",\n            \"answer\": \"因为矩阵乘法的本质是将前一个矩阵的行向量与后一个矩阵的列向量进行内积运算，而内积运算的前提是两个向量的维度必须相同，因此要求前一个矩阵的列数等于后一个矩阵的行数。\"\n        },\n        {\n            \"question\": \"如果需要实现一个原生Python代码来完成矩阵乘法，请简述其实现思路。\",\n            \"answer\": \"实现思路为：1. 遍历前一个矩阵的每一行；2. 对于每一行，遍历后一个矩阵的每一列；3. 计算当前行与当前列的内积（即对应位置元素相乘并求和），并将结果存入结果矩阵的相应位置；4. 最终返回结果矩阵。\"\n        }\n    ]\n}\n', '2025-06-06 21:52:05');
INSERT INTO `videos` VALUES ('2', '向量数据库与Chroma', '20250606_233449_014478.mp4', '312', '智能体开发', '好 那我们今天的内容呢是两个啊 第一个先给大家讲一下向量数据库Chroma的一个应用呃 然后呢 我们再基于LongChain加Chroma再加上前后端交互啊 咱们来实现一个在线智能客服的这么一个项目啊 这个呢 是项目的这么一个界面啊 那么这种智能客服呢它就不是通用的一个这个问答了而是针对一个特定的企业特定的组织它专有的一些指使来回答问题对吧比方说大家可以看到那我呢问这个客服问的都是跟温流学院的培训课程或者说这个公司的一些情况有关的这么一些内容那这就是属于我们的一个向量数据库这么一个应用场景在线智能客服这也是比较常见的应用场景也是我们AI呢目前应用的比较成熟的一个场景我给大家去讲一讲该怎么来做好吧那我们先来聊一聊关于Chroma前面呢我们也给大家提到了项量数据库都知道咋回事所以基本的这些情况呢我就不再过多的去介绍了核心来说呢无非就是将我们的知识或者说我们的文档加载了以后项量化那向量的核心是不是就磁迁入当然你可以用任何的磁迁入模型这儿呢关于磁迁入模型我稍微多说一句我们前边讲自然源处理的时候是给大家讲过怎么来训练这个磁向量的对吧那么同时呢我们已经训练越训练好的这模型那么相当于这个向量呢已经都优化好了事实上这也是我们这个文本计算的最核心的那个这个数据了比方说我们基于这个签问啊基于呃open eye啊gpt或者基于这个bert或者基于各种各样的大模型那好无所谓了那么相当于他们是初始路是不是都是持签路对吧那所以然后在不停的迭代训练的过程当中那么这个向量呢相当于已经是按照最优解来进行训练的所以呢那么我们呢现在啊相当于你就要向量化的话是不是你就需要找一个成熟的模型来进行直迁入这前面我们也有介绍到那么这个模型呢那我们知道在神经网络里边那每一层模型我们都可以单独拼出来那相当于这模型比方说我们使用这个Olama的embedding然后针对着我们用的是这个千万2.5.7B的这个模型那如果你用这个模型当我们在线电话的那些哈这个在线提供的那些APF比方说通议哈当然也都有哈那这呢当我呢说到这儿哈我稍微的再给大家提供一下因为我们前面做实验在线的那个我主要给大家对接的是什么通议签问和定性对吧事实上呢还有一个叫这个字谱啊字谱AI一个模特质朴AI也不错大家如果有心血可以去测试一下看看效果然后质朴AI价格也比较便宜跟低谱这个差不多对吧你看我充了20块钱到现在都没用多少对吧用的很少但因为平时做实验偏多一点还是用的欧拉玛而已用这个在线的用的没有那么多那么所以呢大家也可以来去这个质朴上边去注册一个账号来体验一下那字谱这边的开发文档呢也是相对还比较全面的那么用字谱有个好处就是它既提供了这个文本的生成又提供了这个多模态的视觉识笔同时呢它也具备文生图的能力CogView和文生视频的CogVideo当然还包括我们的一些磁迁入的向量的一个运算那么这边呢就是给大家说一下那他同样的支持sdkpython的stk和java的sdk他都是支持的提供python和java同样的也支持http这个调用也支持http协议的调用那这些呢当然常过来说都是ok的我们通议签问同样也可以使用desic scope同样的也可以使用http协议是吧直接发请求的方式调用都没有问题那BIGMO那个字谱如果它的官网叫BIGMO的而已这个字谱AI呢模型呢好评度也还不错是吧关键呢对我们来说一方面接口也比较简单另外呢它支持的模型跟通议签问一样也比较多对吧支持视觉当然签问的系列同样也支持通议签问也支持文本然后文本视觉VL以及文身图', '<h2>课程笔记：基于Chroma向量数据库和LongChain实现在线智能客服</h2>\n\n<p>今天的内容分为两个部分：第一部分介绍向量数据库Chroma的应用场景；第二部分基于LongChain、Chroma以及前后端交互，实现一个针对特定企业或组织的在线智能客服系统。</p>\n\n<h3>一、向量数据库Chroma的应用场景</h3>\n\n<p>向量数据库Chroma是一种专门用于存储和检索高维向量数据的工具，常用于自然语言处理（NLP）等领域的文本相似度计算。在实际应用中，我们可以将企业的文档、知识库等信息加载到Chroma中，并通过嵌入模型（Embedding Model）将其转化为向量形式，从而实现高效的知识检索。</p>\n\n<p>具体来说：</p>\n<ul>\n    <li>将企业的文档或知识库加载到Chroma中。</li>\n    <li>使用嵌入模型将文本转化为向量。</li>\n    <li>通过向量检索技术，快速找到与用户问题最相关的答案。</li>\n</ul>\n\n<p>这种在线智能客服系统的特点是针对特定企业或组织的专有知识进行问答，而不是通用的问答系统。例如，它可以回答关于某公司培训课程或公司情况的具体问题。</p>\n\n<h3>二、嵌入模型的选择与训练</h3>\n\n<p>嵌入模型是向量数据库的核心，它决定了文本向量化的效果。以下是一些常见的嵌入模型及其特点：</p>\n\n<ul>\n    <li><strong>OpenAI GPT系列：</strong>适合高质量的文本生成任务，但成本较高。</li>\n    <li><strong>BERT：</strong>广泛应用于文本分类、问答等任务。</li>\n    <li><strong>Olama Embedding：</strong>我们之前实验中常用的一个模型，效果不错。</li>\n    <li><strong>字谱AI（Zhipu AI）：</strong>一个性价比较高的国产模型，支持文本生成、多模态视觉识别以及文生图等功能。</li>\n</ul>\n\n<p>在选择嵌入模型时，需要综合考虑模型性能、成本以及具体应用场景。例如，字谱AI提供了一个简单易用的接口，同时支持Python和Java SDK，也支持HTTP协议调用，非常适合快速开发。</p>\n\n<h3>三、项目实现：基于LongChain、Chroma和前后端交互的智能客服</h3>\n\n<p>接下来，我们将基于LongChain框架、Chroma向量数据库以及前后端交互技术，实现一个在线智能客服系统。以下是项目的实现步骤：</p>\n\n<ol>\n    <li><strong>数据准备：</strong>收集并整理企业的文档或知识库。</li>\n    <li><strong>向量化处理：</strong>使用嵌入模型将文档转化为向量，并存储到Chroma数据库中。</li>\n    <li><strong>后端开发：</strong>基于LongChain框架构建后端逻辑，实现用户提问与知识库检索的对接。</li>\n    <li><strong>前端开发：</strong>设计用户界面，允许用户输入问题并展示答案。</li>\n    <li><strong>API调用：</strong>通过HTTP协议调用字谱AI或其他大模型的接口，完成复杂问题的生成性回答。</li>\n</ol>\n\n<p>此外，还可以根据需求扩展系统的功能，例如支持多模态查询（如图片识别）或生成可视化内容（如文生图）。</p>\n\n<h3>四、总结</h3>\n\n<p>本节课主要介绍了如何利用Chroma向量数据库和嵌入模型实现一个针对特定企业或组织的在线智能客服系统。通过LongChain框架和前后端交互技术，可以快速搭建一个功能完善的智能客服平台。推荐大家尝试使用字谱AI等国产模型，体验其高效、低成本的优势。</p>', '向量数据库与智能客服', '[{\'link\': \'https://baike.baidu.com/item/%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93/63110709\', \'title\': \'向量数据库\', \'content\': \'向量数据库\\n向量数据库是专门用来存储和查询向量的数据库，其存储的向量来自于对文本、语音、图像、视频等的向量化。与传统数据库相比，向量数据库可以处理更多非结构化数据（比如图像和音频）。在机器学习和深度学习中，数据通常以向量形式表示。\', \'snippet\': \'向量数据库是专门用来存储和查询向量的数据库，其存储的向量来自于对文本、语音、图像、视频等的向量化。与传统数据库相比，向量数据库可以处理更多非结构化数据（比如图像和音频）。在机器学习和深度学习中，数据通常以向量形式表示。\', \'position\': None}, {\'link\': \'https://www.bilibili.com/read/mobile?id=40082102\', \'title\': \'深度分析 | 2024主流的智能客服系统有哪些？他们是怎么实现的？\', \'content\': \'深度分析 | 2024主流的智能客服系统有哪些？他们是怎么实现的？\\n一、智能客服系统的使用方法1. 前端交互层： 用户与智能客服系统直接接触的界面。企业在网页、移动应用程序或社交媒体等渠道设置咨询入口，客户点击后可以选择以语音、文字、视频等方式与系统进行沟通。2. 服务层接入： 接收前端交互层传来的用户请求。系统支持各种通信协议，如HTTP、WebSocket等，能够确保用户与系统之间交互数据准确无误的传输，提供稳定流畅的即时通讯服务。3. 逻辑层处理： 作为核心部分，承担着对话处理、意图识别和响应生成等任务。能够深度解析用户输入，精准识别意图，运用机器学习与自然语言处理技术生成回应，并依据用户交互持续优化自身逻辑，提升应答质量。4. 数据层存储： 存储用户信息、交互记录与知识库内容，采用加密与严格访问权限控制保障数据安全，防止信息泄露与篡改。\', \'snippet\': \'一、智能客服系统的使用方法1. 前端交互层： 用户与智能客服系统直接接触的界面。企业在网页、移动应用程序或社交媒体等渠道设置咨询入口，客户点击后可以选择以语音、文字、视频等方式与系统进行沟通。2. 服务层接入： 接收前端交互层传来的用户请求。系统支持各种通信协议，如HTTP、WebSocket等，能够确保用户与系统之间交互数据准确无误的传输，提供稳定流畅的即时通讯服务。3. 逻辑层处理： 作为核心部分，承担着对话处理、意图识别和响应生成等任务。能够深度解析用户输入，精准识别意图，运用机器学习与自然语言处理技术生成回应，并依据用户交互持续优化自身逻辑，提升应答质量。4. 数据层存储： 存储用户信息、交互记录与知识库内容，采用加密与严格访问权限控制保障数据安全，防止信息泄露与篡改。\', \'position\': None}, {\'link\': \'https://m.blog.csdn.net/u013172930/article/details/147399635\', \'title\': \'什么是 向量数据库（Vector Database）\', \'content\': \'什么是 向量数据库（Vector Database）\\n向量数据库（Vector Database）是一种专门设计用于存储、索引和管理高维向量数据的数据库系统。这些向量通常是机器学习模型（如深度学习模型）生成的嵌入（embeddings），用于表示文本、图像、音频等数据的语义特征。向量数据库的核心目标是高效地支持向量相似性搜索（Similarity Search），\', \'snippet\': \'向量数据库（Vector Database）是一种专门设计用于存储、索引和管理高维向量数据的数据库系统。这些向量通常是机器学习模型（如深度学习模型）生成的嵌入（embeddings），用于表示文本、图像、音频等数据的语义特征。向量数据库的核心目标是高效地支持向量相似性搜索（Similarity Search），\', \'position\': None}, {\'link\': \'https://baijiahao.baidu.com/s?id=1796653068244076418\', \'title\': \'智能客服功能是如何实现的？\', \'content\': \'智能客服功能是如何实现的？\\n在智能客服功能的应用场景中，最常见的形式是智能客服机器人。智能客服机器人可以通过网站、APP、微信公众号等多种渠道与用户进行交互，为用户提供24小时不间断的服务。此外，智能客服机器人还可以被应用于电商、金融、医疗等领域，为各行各业提供智能化的客户服务。 未来随着人工智能技术的不断发展和进步，智能客服功能也将迎来更加广阔的发展空间。\', \'snippet\': \'在智能客服功能的应用场景中，最常见的形式是智能客服机器人。智能客服机器人可以通过网站、APP、微信公众号等多种渠道与用户进行交互，为用户提供24小时不间断的服务。此外，智能客服机器人还可以被应用于电商、金融、医疗等领域，为各行各业提供智能化的客户服务。 未来随着人工智能技术的不断发展和进步，智能客服功能也将迎来更加广阔的发展空间。\', \'position\': None}]', '\n{\n  \"meta\": {\n    \"name\": \"向量数据库与智能客服\",\n    \"author\": \"AI生成\",\n    \"version\": \"1.0\"\n  },\n  \"format\": \"node_tree\",\n  \"data\": {\n    \"id\": \"1\",\n    \"topic\": \"向量数据库Chroma与在线智能客服\",\n    \"children\": [\n      {\n        \"id\": \"1-1\",\n        \"topic\": \"项目概述\",\n        \"children\": [\n          {\n            \"id\": \"1-1-1\",\n            \"topic\": \"目标：实现基于LongChain+Chroma的在线智能客服\"\n          },\n          {\n            \"id\": \"1-1-2\",\n            \"topic\": \"应用场景：企业专有知识问答（如培训课程、公司情况）\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-2\",\n        \"topic\": \"Chroma数据库的核心功能\",\n        \"children\": [\n          {\n            \"id\": \"1-2-1\",\n            \"topic\": \"将文档或知识进行向量化处理\"\n          },\n          {\n            \"id\": \"1-2-2\",\n            \"topic\": \"使用预训练模型优化向量（如OpenAI GPT、BERT等）\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-3\",\n        \"topic\": \"向量化的技术细节\",\n        \"children\": [\n          {\n            \"id\": \"1-3-1\",\n            \"topic\": \"嵌入模型（Embedding Model）的选择\"\n          },\n          {\n            \"id\": \"1-3-2\",\n            \"topic\": \"示例模型：Olama Embedding (13B参数)\"\n          },\n          {\n            \"id\": \"1-3-3\",\n            \"topic\": \"其他在线API支持（如通义千问、字谱AI）\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-4\",\n        \"topic\": \"推荐的AI模型与服务\",\n        \"children\": [\n          {\n            \"id\": \"1-4-1\",\n            \"topic\": \"字谱AI：多模态能力（文本生成、视觉识别、文生图等）\"\n          },\n          {\n            \"id\": \"1-4-2\",\n            \"topic\": \"支持的语言与协议：Python SDK、Java SDK、HTTP调用\"\n          },\n          {\n            \"id\": \"1-4-3\",\n            \"topic\": \"优点：价格便宜、接口简单、模型种类丰富\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-5\",\n        \"topic\": \"技术实现与调用方式\",\n        \"children\": [\n          {\n            \"id\": \"1-5-1\",\n            \"topic\": \"通义千问：支持Desic Scope与HTTP协议调用\"\n          },\n          {\n            \"id\": \"1-5-2\",\n            \"topic\": \"字谱AI：支持Python和Java SDK，兼容HTTP请求\"\n          }\n        ]\n      }\n    ]\n  }\n}\n', '\n{\n    \"choices\": [\n        {\n            \"question\": \"以下哪一项是向量数据库Chroma的主要应用场景？\",\n            \"options\": {\n                \"A\": \"通用搜索引擎优化\",\n                \"B\": \"在线智能客服\",\n                \"C\": \"实时数据流处理\",\n                \"D\": \"大规模图像分类\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"在神经网络中，用于生成向量的模型可以被称为：\",\n            \"options\": {\n                \"A\": \"磁迁入模型\",\n                \"B\": \"卷积神经网络\",\n                \"C\": \"循环神经网络\",\n                \"D\": \"支持向量机\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"关于Chroma数据库的应用，以下哪项描述正确？\",\n            \"options\": {\n                \"A\": \"主要用于通用问答任务\",\n                \"B\": \"仅支持文本数据的存储\",\n                \"C\": \"适用于特定领域知识的问答系统\",\n                \"D\": \"不支持与前后端交互\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"以下哪个模型可以用于生成高质量的文本嵌入向量？\",\n            \"options\": {\n                \"A\": \"BERT\",\n                \"B\": \"ResNet\",\n                \"C\": \"YOLO\",\n                \"D\": \"VGG16\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"Olama embedding使用的具体模型版本为：\",\n            \"options\": {\n                \"A\": \"7B\",\n                \"B\": \"2.5B\",\n                \"C\": \"10B\",\n                \"D\": \"1.5B\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"以下哪一项不是质朴AI提供的功能？\",\n            \"options\": {\n                \"A\": \"文本生成\",\n                \"B\": \"多模态视觉识别\",\n                \"C\": \"文生图\",\n                \"D\": \"硬件加速计算\"\n            },\n            \"answer\": \"D\"\n        },\n        {\n            \"question\": \"通议千问支持哪些调用方式？（多选）\",\n            \"options\": {\n                \"A\": \"SDK (Python)\",\n                \"B\": \"SDK (Java)\",\n                \"C\": \"HTTP协议调用\",\n                \"D\": \"命令行工具\"\n            },\n            \"answer\": \"ABC\"\n        },\n        {\n            \"question\": \"以下哪一项是质朴AI的优点？\",\n            \"options\": {\n                \"A\": \"接口复杂但功能强大\",\n                \"B\": \"价格低廉且接口简单\",\n                \"C\": \"仅支持单一模型\",\n                \"D\": \"不支持多模态任务\"\n            },\n            \"answer\": \"B\"\n        }\n    ],\n    \"qas\": [\n        {\n            \"question\": \"请简述向量数据库Chroma的核心功能及其应用场景。\",\n            \"answer\": \"向量数据库Chroma的核心功能是将知识或文档转化为向量进行存储和检索。其主要应用场景包括在线智能客服、特定领域的问答系统等，能够针对企业或组织的专有知识提供高效的查询服务。\"\n        },\n        {\n            \"question\": \"什么是磁迁入模型？它在自然语言处理中的作用是什么？\",\n            \"answer\": \"磁迁入模型是一种用于生成文本嵌入向量的深度学习模型。在自然语言处理中，它的作用是将文本转化为高维向量表示，从而捕捉语义信息，为后续任务（如分类、检索、生成等）提供基础数据支持。\"\n        },\n        {\n            \"question\": \"对比通议千问和质朴AI，分析它们各自的优缺点。\",\n            \"answer\": \"通议千问的优点是支持多种模型和任务，功能全面；缺点是接口相对复杂。质朴AI的优点是价格低廉、接口简单，同时支持多模态任务；缺点是功能可能不如通议千问丰富。根据实际需求选择合适的工具更为重要。\"\n        }\n    ]\n}\n', '2025-06-06 23:39:18');
INSERT INTO `videos` VALUES ('3', '多头自注意力原理', '20250606_235108_964132.mp4', '310', '大模型原理', '关于那个位置编码还有一个小点哈我再给他补充一下就好了那个我们看这边是不要求距离应该一致或者说是等长的线性相关的对吧啊怎么能看出来线性相关呢大家不用看这个值哈这儿你看这个值你暂时看不出来有什么相关性啊 我们看公式就行了公式大家看啊 比方说我的pos这个假设是01啊 也就是第一个第0个位置 以及11 以及2131是不是同一个向量 同一个向量 然后对应的是不同的几个词 是吧不同的几个token0123这几个token那么这边呢假设我们是n个维度无所谓多少个维度嘛就d嘛d个维度d分之多少是不是2i然后这边是什么predation对吧这个公式是不是这个样子的那你看哈ii数相同的反正都是什么第二个向量假设哈随便举一个例子那对应的四个词呢 它的位置 你看啊 是不是presentation要变的部分是哪里呢那presentation呢 首先是不是0 后边呢 又变成了什么下一个位置相同的地方 是不是又变成了1所以又变成了2又变成了3其他地方是不是都没变那相当于你看它是不是属于线性相关的那我求这个相当于它是等于什么3下边分母不变我就随便又给X表示了嘛都没变嘛上边呢是不是0我求这个呢就变成了什么3加上什么 还是一我求这个呢是不是相当于是什么x1加上x1x1加一个是不就变成x2了吗对吧 那对的不就分子为二吗 那如果三了是不是就是什么是不是再加上x1啊再加上X1当然我这少起来个X0了如果3的话是不是再加个X1你看啊他们是不是线性相关的啊虽然听过三眼影求出来的值他不是一个说什么等差的但是呢他的这个公式我们能看出来是不是他们都是位置都是一个一个往后加针对I是同一个维度的情况下分母是不不变的那三眼影扩展影交替的一个一个往后加嘛是不是这个逻辑啊这就看着一个规律了所以他能够知道哪个位置在前哪个位置在后对吧就这么个逻辑好吧就这样了那这个呢我们就是关于位置边码这边哈稍微再说一下这个一万呢你也可以取成一千也可以取成十万也可以取成一百之所以取一万呢是大家经过计算经过经验表明一万因为一万一个什么概念1万的话让这个也就意味着它的变化空间可以是0.0001到1我看我在哪写过没编码在非常宽的范围内分布万分之一到一这个是什么概念2i除以d好我们来看看哈是不是分母predation分子是1万分的2i除以d次方2i除以d次方啊2i等于0的时候万分万一万的零次方是不是最大取到一个最大值一好最小值那是什么情况那就是i正好等于二分之 d的时候2i是不是就是等于什么i是二分之 d嘛2i就正好是什么等于 d那这边得到的是什么是不是就是1i等于最大值二分之 d的时候二分之 d就二那个这个啊2k加1那么得到它的最大值的时候是不是就是这个指数啊就是', '<h3>课程笔记：位置编码与线性相关性</h3>\n\n<p>本节课主要讲解了位置编码的相关内容，重点分析了其公式以及如何通过公式判断向量的线性相关性。</p>\n\n<h4>1. 位置编码的基本概念</h4>\n<p>位置编码的核心思想是为每个词（token）赋予一个与其位置相关的向量表示。这些向量不需要满足距离一致或等长的要求，但需要能够反映词的位置关系。</p>\n\n<h4>2. 公式分析</h4>\n<p>假设位置编码的维度为 \\(d\\)，对于第 \\(pos\\) 个位置，其向量的第 \\(i\\) 维可以表示为：</p>\n\\[\nPE_{(pos, 2i)} = \\sin\\left(\\frac{pos}{10000^{2i/d}}\\right), \\quad PE_{(pos, 2i+1)} = \\cos\\left(\\frac{pos}{10000^{2i/d}}\\right)\n\\]\n<p>其中，\\(10000\\) 是一个经验值，目的是让编码值在范围 \\([0.0001, 1]\\) 内分布，从而确保变化空间足够宽广。</p>\n\n<h4>3. 线性相关性的判断</h4>\n<p>通过公式可以看出，不同位置的向量虽然看起来没有明显的规律，但实际上具有一定的线性相关性。例如：</p>\n<ul>\n    <li>对于同一个维度 \\(i\\)，随着位置 \\(pos\\) 的增加，向量的值呈现周期性变化。</li>\n    <li>具体来说，如果将某个位置的向量表示为 \\(X_0\\)，那么下一个位置的向量可以近似表示为 \\(X_1 = X_0 + \\Delta\\)，即它们之间存在线性递推关系。</li>\n</ul>\n\n<h4>4. 关于 \\(10000\\) 的选择</h4>\n<p>\\(10000\\) 是一个经验值，用于控制位置编码的变化范围。当 \\(2i/d\\) 较小时，变化较慢；当 \\(2i/d\\) 较大时，变化较快。这种设计使得低频部分可以捕捉更长的依赖关系，而高频部分则能区分更短的距离。</p>\n\n<h4>5. 总结</h4>\n<p>位置编码通过特定公式生成向量，能够有效反映词的位置信息，并且这些向量在某些维度上表现出线性相关性。选择 \\(10000\\) 作为基数是为了确保编码值在合理范围内分布，从而更好地适应模型的需求。</p>', '位置编码', '[{\'link\': \'https://m.blog.csdn.net/Recursions/article/details/141369275\', \'title\': \'NLP位置编码\', \'content\': \'NLP位置编码\\n在自然语言处理和深度学习中，位置编码（Position Encoding）是一种为了向模型中引入序列中元素位置信息的技术。当处理序列数据时，如文本句子或时间序列数据，模型通常需要考虑元素的顺序和位置关系。仅仅依靠原始的词向量或特征表示往往无法捕捉到位置信息，而位置编码则可以有效地将位置信息融入到模型的输入中。\', \'snippet\': \'在自然语言处理和深度学习中，位置编码（Position Encoding）是一种为了向模型中引入序列中元素位置信息的技术。当处理序列数据时，如文本句子或时间序列数据，模型通常需要考虑元素的顺序和位置关系。仅仅依靠原始的词向量或特征表示往往无法捕捉到位置信息，而位置编码则可以有效地将位置信息融入到模型的输入中。\', \'position\': None}, {\'link\': \'https://m.blog.csdn.net/m0_74052450/article/details/146986226\', \'title\': \'位置编码（Positional Encoding, PE）的作用\', \'content\': \'位置编码（Positional Encoding, PE）的作用\\n位置编码的核心作用是为模型补充序列的顺序信息，使其能正确处理时序或结构依赖关系。它是Transformer等非序列模型的必备组件，直接影响模型对上下文的理解能力。选择何种编码方式（固定/可学习、绝对/相对）需根据任务需求和数据特性权衡。\', \'snippet\': \'位置编码的核心作用是为模型补充序列的顺序信息，使其能正确处理时序或结构依赖关系。它是Transformer等非序列模型的必备组件，直接影响模型对上下文的理解能力。选择何种编码方式（固定/可学习、绝对/相对）需根据任务需求和数据特性权衡。\', \'position\': None}, {\'link\': \'https://m.blog.csdn.net/qq_26169815/article/details/144880811\', \'title\': \'位置编码--RoPE\', \'content\': \'位置编码--RoPE\\n在标准的Transformer模型中，位置编码（Positional Encoding，PE）通常通过固定的正弦和余弦函数生成，旨在为模型提供序列中各个元素的位置。这个方法的一个潜在问题是，它对于长序列的泛化能力较差，尤其是在处理长文本或其他复杂的序列数据时，传统的位置编码可能无法很好地捕捉到长距离的依赖关系。1.1 前置概念： Transformer 中位置嵌入的必要性 为了理解 RoPE 的重要性，我们首先回顾一下为什么位置...\', \'snippet\': \'在标准的Transformer模型中，位置编码（Positional Encoding，PE）通常通过固定的正弦和余弦函数生成，旨在为模型提供序列中各个元素的位置。这个方法的一个潜在问题是，它对于长序列的泛化能力较差，尤其是在处理长文本或其他复杂的序列数据时，传统的位置编码可能无法很好地捕捉到长距离的依赖关系。1.1 前置概念： Transformer 中位置嵌入的必要性 为了理解 RoPE 的重要性，我们首先回顾一下为什么位置...\', \'position\': None}, {\'link\': \'https://m.blog.csdn.net/u013172930/article/details/145607554\', \'title\': \'位置编码（Positional Encoding）\', \'content\': \'位置编码（Positional Encoding）\\n位置编码（Positional Encoding）  是一种向量表示，用于 编码输入序列中各个元素的位置信息 。由于  Transformer  模型（及其变种）基于自注意力（Self-Attention）机制，它本身并不具备序列顺序的固有表示，因此必须通过位置编码来补充序列中的位置信息。 ...\', \'snippet\': \'位置编码（Positional Encoding）  是一种向量表示，用于 编码输入序列中各个元素的位置信息 。由于  Transformer  模型（及其变种）基于自注意力（Self-Attention）机制，它本身并不具备序列顺序的固有表示，因此必须通过位置编码来补充序列中的位置信息。 ...\', \'position\': None}]', '\n{\n  \"meta\": {\n    \"name\": \"位置编码\",\n    \"author\": \"AI生成\",\n    \"version\": \"1.0\"\n  },\n  \"format\": \"node_tree\",\n  \"data\": {\n    \"id\": \"1\",\n    \"topic\": \"位置编码的核心概念\",\n    \"children\": [\n      {\n        \"id\": \"1-1\",\n        \"topic\": \"线性相关性的判断\",\n        \"children\": [\n          {\n            \"id\": \"1-1-1\",\n            \"topic\": \"通过公式分析位置向量的特性\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-1-2\",\n            \"topic\": \"不同位置对应不同的token\",\n            \"children\": []\n          }\n        ]\n      },\n      {\n        \"id\": \"1-2\",\n        \"topic\": \"公式解析\",\n        \"children\": [\n          {\n            \"id\": \"1-2-1\",\n            \"topic\": \"pos表示位置，d表示维度\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-2-2\",\n            \"topic\": \"分母为2i/d，分子为位置值\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-2-3\",\n            \"topic\": \"呈现规律：位置值依次递增\",\n            \"children\": []\n          }\n        ]\n      },\n      {\n        \"id\": \"1-3\",\n        \"topic\": \"取值范围与经验选择\",\n        \"children\": [\n          {\n            \"id\": \"1-3-1\",\n            \"topic\": \"常取值为10000（也可为1000或100000）\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-3-2\",\n            \"topic\": \"变化空间范围：0.0001到1\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-3-3\",\n            \"topic\": \"最大值与最小值分析\",\n            \"children\": [\n              {\n                \"id\": \"1-3-3-1\",\n                \"topic\": \"最大值：当2i/d=0时，结果为1\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-3-3-2\",\n                \"topic\": \"最小值：当2i/d=d时，结果接近0\",\n                \"children\": []\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"id\": \"1-4\",\n        \"topic\": \"规律总结\",\n        \"children\": [\n          {\n            \"id\": \"1-4-1\",\n            \"topic\": \"位置编码能够体现前后顺序关系\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-4-2\",\n            \"topic\": \"同一维度下，位置值按固定规律递增\",\n            \"children\": []\n          }\n        ]\n      }\n    ]\n  }\n}\n', '\n{\n    \"choices\": [\n        {\n            \"question\": \"位置编码中，假设pos为01、11、21、31时，这些位置对应的向量是否相同？\",\n            \"options\": {\n                \"A\": \"完全相同\",\n                \"B\": \"部分相同\",\n                \"C\": \"完全不同\",\n                \"D\": \"无法判断\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"在位置编码公式中，分母的值由什么决定？\",\n            \"options\": {\n                \"A\": \"pos的值\",\n                \"B\": \"d_model的值\",\n                \"C\": \"i的值\",\n                \"D\": \"以上都不对\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"为什么通常将位置编码中的基数取为10000？\",\n            \"options\": {\n                \"A\": \"方便计算\",\n                \"B\": \"经验值表明效果较好\",\n                \"C\": \"便于存储\",\n                \"D\": \"随机选择\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"位置编码中，当i等于d/2时，指数的最大值是多少？\",\n            \"options\": {\n                \"A\": \"1\",\n                \"B\": \"d\",\n                \"C\": \"d/2\",\n                \"D\": \"2i\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"位置编码公式的分子部分是什么？\",\n            \"options\": {\n                \"A\": \"pos\",\n                \"B\": \"10000^(2i/d)\",\n                \"C\": \"pos * 10000^(2i/d)\",\n                \"D\": \"pos / 10000^(2i/d)\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"在位置编码中，如何通过公式确定不同词的位置关系？\",\n            \"options\": {\n                \"A\": \"通过距离的线性相关性\",\n                \"B\": \"通过向量的模长\",\n                \"C\": \"通过角度的余弦值\",\n                \"D\": \"通过位置索引的绝对值\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"在位置编码中，若i固定，随着pos增加，向量的变化规律是？\",\n            \"options\": {\n                \"A\": \"呈等差数列变化\",\n                \"B\": \"呈等比数列变化\",\n                \"C\": \"呈线性相关变化\",\n                \"D\": \"无规律变化\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"在位置编码中，若i=0，则分子的最大值是多少？\",\n            \"options\": {\n                \"A\": \"1\",\n                \"B\": \"0.0001\",\n                \"C\": \"10000\",\n                \"D\": \"d_model\"\n            },\n            \"answer\": \"A\"\n        }\n    ],\n    \"qas\": [\n        {\n            \"question\": \"解释一下为什么位置编码可以表示词语之间的相对位置关系？\",\n            \"answer\": \"位置编码通过引入sin和cos函数，使得不同位置的编码具有周期性和相对性，从而能够反映词语之间的相对位置关系。例如，通过公式计算，即使位置发生变化，其相对关系仍可以通过编码体现出来。\"\n        },\n        {\n            \"question\": \"请说明位置编码中10000^(2i/d)的作用及其意义。\",\n            \"answer\": \"10000^(2i/d)用于控制位置编码的变化范围，确保不同维度上的变化幅度适中。它使得低频位置信息（较大的i）变化较慢，而高频位置信息（较小的i）变化较快，从而更好地捕捉词语之间的相对位置关系。\"\n        },\n        {\n            \"question\": \"如何通过位置编码公式验证两个词的位置是否线性相关？\",\n            \"answer\": \"通过位置编码公式，我们可以观察到同一维度下，随着位置索引pos的变化，向量值呈现线性递增或递减的关系。因此，如果两个词的位置编码在某些维度上满足这种线性递增或递减关系，则可以认为它们的位置是线性相关的。\"\n        }\n    ]\n}\n', '2025-06-06 23:55:18');
INSERT INTO `videos` VALUES ('4', '梯度下降的原理', '20250607_000708_097411.mp4', '308', '神经网络', '好 那我们通过最小二层法的方式啊就可以计算出来这个公式对吧 大家刚才做完练习多少应该也有点概念了相当于哈 我们呢 理合出来了一个a和b的值 进而得到一个标准的一元线性方程然后根据X来预测啊我们就其实就达到了预测目的那其实机器学习都是在做各种各样的预测啊我们呢其实平常做一些数据的挖掘也是干的就这个事情从已有的历史数据我们去分析和挖掘出来一些有价值的规律进而呢进行总结进行分类或者说进行对未来数值的一个预测这个呢 其实无论用怎么的方式来描述他们的作用啊 都是差不多的就是预测 哪怕就是一个分类啊就是一个分类那比方说啊 有没有购买意向啊是不是优质客户完了以后呢 或者说哈 这个我呢 根据以前的来预测现在的销售额对吧 我根据呢 也有的这些购买数据啊我来预测哪种产品是这个这个大家最喜爱的或者我去预测用户买A产品的时候买B产品的概率大概有多高他们在一起的这个关联度高不高等等这其实都可以把它归结为什么预测的一个视角来看待包括甚至我们的后边的什么计算机视觉里边的这些这个图像的识别处理也是一种预测预测谁的概率更高一些了好那么另外呢那我们做这种事情其实就我刚才给他强调过两种方案第一种呢叫做数学和统计学的角度其实我们最小二层法做的这个线性回归一元的线性回归就是一个纯数学的方式或者说统计学的角度来处理那我们机器学习呢由于它面临的很多这个方程肯定都不单纯这么简单甚至神经网络我们呢方程可能会更复杂甚至方程数量更多所以在这种情况下机器学习就试图呢要去找到一个更加通用的办法来进行这个函数的一个理合对吧找到他们的这些权重甚至包括多元先行回归那有很多因素那我们的这个最小二层法呢这个就很难去算了对吧所以我们呢需要去找到一个针对计算机计算机能干什么事情计算机就适合做呢运算所以其实你看哈我们有时候解方程解方程我们有两种两种思路大家想想像刚才我讲的最小二层法这种是不是算或者比方说哈我举个例子这个叫什么鸡兔同龙这也是一个比较经典的一个这个数学算法的问题对吧完了以后呢有若干之鸡然后从上面数有35个头下面数有94只脚请问龙中有多少只鸡和多少只兔就这么一个数学问题我们有两种方案有两种方案来算第一种方案啊就是按照数学公式按照数学公式按照数学公式怎么算那无非就是那个头有35个那么x假设是gy假设是2那x加y等于35对吧列方程嘛然后第二个呢有94只脚然后x是gY是2啊那G呢是2XG的角只有两只然后2的话呢是4值4Y等于多少等于94这是不是一个二元方程对吧然后呢有两个方程组构成这是不是可以求解的可以求解的对吧可以求解那两个次子相减那就X加3Y等于多少94-3559那算出来X和Y的关系X就等于什么59减3Y对吧这叫数学方式运算那59减3Y带入X加Y那说完了是不是就是59减2Y等于35那么好2Y就等于多少59减35', '<div>\n    <h3>课程笔记：机器学习与预测方法</h3>\n    <p>本节课主要讲解了通过最小二乘法计算一元线性回归公式，并探讨了机器学习在预测中的应用。</p>\n    \n    <h4>1. 最小二乘法与一元线性回归</h4>\n    <p>通过最小二乘法，我们可以计算出一个标准的一元线性方程。该方法的核心是找到最佳的参数 \\(a\\) 和 \\(b\\)，从而得到一个线性模型 \\(y = ax + b\\)。利用这个模型，我们可以通过已知的 \\(x\\) 值来预测 \\(y\\) 的值，从而实现预测的目的。</p>\n    \n    <h4>2. 机器学习的本质——预测</h4>\n    <p>机器学习的主要目标是基于历史数据进行预测。无论是分类问题（如判断客户是否有购买意向、是否为优质客户），还是数值预测（如销售额预测、产品偏好预测），都可以归结为预测问题。</p>\n    \n    <h4>3. 数学与统计学角度 vs. 机器学习方法</h4>\n    <ul>\n        <li><strong>数学与统计学角度：</strong> 使用最小二乘法等传统数学方法解决简单问题，例如一元线性回归。</li>\n        <li><strong>机器学习方法：</strong> 面对更复杂的模型（如多元线性回归、神经网络），机器学习通过寻找通用的函数拟合方法，计算权重和参数，适应复杂场景。</li>\n    </ul>\n    \n    <h4>4. 计算机运算的特点</h4>\n    <p>计算机擅长处理大规模的运算任务。以“鸡兔同笼”问题为例，我们可以通过以下两种方法求解：</p>\n    <ol>\n        <li><strong>数学公式法：</strong> 设鸡的数量为 \\(x\\)，兔的数量为 \\(y\\)，根据题意列出两个方程：\n            <ul>\n                <li>\\(x + y = 35\\)（头的数量）</li>\n                <li>\\(2x + 4y = 94\\)（脚的数量）</li>\n            </ul>\n            通过代入消元法，可以解得 \\(x\\) 和 \\(y\\) 的关系。</li>\n        <li><strong>计算机运算法：</strong> 对于更复杂的问题，计算机可以通过迭代或其他算法快速求解。</li>\n    </ol>\n    \n    <p>总结：最小二乘法是一种经典的数学方法，适用于简单问题；而机器学习则通过更通用的函数拟合方法，解决了复杂场景下的预测问题。两者的核心都是通过已有数据进行规律挖掘和未来预测。</p>\n</div>', '预测', '[{\'link\': \'https://baike.baidu.com/item/%E9%A2%84%E6%B5%8B/35966\', \'title\': \'预测汉语词语\', \'content\': \'预测汉语词语\\n预测，汉语词语，读音：yù cè，注音：ㄩˋ ㄘㄜˋ 意思是预先测定或推测。[forecast;calculate] 预先测定或推测陈田 《明诗纪事丙签·林潮》1、预先推测或测定。陈田 《明诗纪事丙签·林潮》：“一家五尚书，三祭酒，三世諡文，非独 明 代仅见，古亦罕有其伦也……纵极力颂扬，安能预测子姓如此之盛耶。茅盾 《子夜》五：“他对于此番的工潮不能预测，甚至即在昨天还没有正确地估量到工人力量的雄大。\', \'snippet\': \'预测，汉语词语，读音：yù cè，注音：ㄩˋ ㄘㄜˋ 意思是预先测定或推测。[forecast;calculate] 预先测定或推测陈田 《明诗纪事丙签·林潮》1、预先推测或测定。陈田 《明诗纪事丙签·林潮》：“一家五尚书，三祭酒，三世諡文，非独 明 代仅见，古亦罕有其伦也……纵极力颂扬，安能预测子姓如此之盛耶。茅盾 《子夜》五：“他对于此番的工潮不能预测，甚至即在昨天还没有正确地估量到工人力量的雄大。\', \'position\': None}, {\'link\': \'https://www.zdic.net/hans/%E9%A2%84%E6%B5%8B\', \'title\': \'预测\', \'content\': \'预测\\n预测 yùcè [forecast;calculate] 预先测定或推测 预测是指在掌握现有信息的基础上，依照一定的方法和规律对未来的事情进行测算，以预先了解事情发展的过程与结果。\', \'snippet\': \'预测 yùcè [forecast;calculate] 预先测定或推测 预测是指在掌握现有信息的基础上，依照一定的方法和规律对未来的事情进行测算，以预先了解事情发展的过程与结果。\', \'position\': None}, {\'link\': \'http://www.newxue.com/dict/124331846964660.html\', \'title\': \'预测\', \'content\': \'预测\\nLife is full of uncertainty.Predict(results)based on known data;extrapolate(根据现有资料)预测(结果);推断As Goldman Sachs notes, inflation was 3.2 per cent in the year to December against minus 0.4 per cent a year before.高盛(Goldman Sachs)预测，在截至去年1...\', \'snippet\': \'Life is full of uncertainty.Predict(results)based on known data;extrapolate(根据现有资料)预测(结果);推断As Goldman Sachs notes, inflation was 3.2 per cent in the year to December against minus 0.4 per cent a year before.高盛(Goldman Sachs)预测，在截至去年1...\', \'position\': None}, {\'link\': \'https://wiki.mbalib.com/wiki/%E9%A2%84%E6%B5%8B\', \'title\': \'预测\', \'content\': \'预测\\n上面这些步骤系统总结了开始、设计和应用一项预测的各环节。如果是定期做预测，数据则应定期收集。实际运算则可由计算机进行。预测的重要意义[1] 预测的重要意义就在于它能够在自觉地认识客...\', \'snippet\': \'上面这些步骤系统总结了开始、设计和应用一项预测的各环节。如果是定期做预测，数据则应定期收集。实际运算则可由计算机进行。预测的重要意义[1] 预测的重要意义就在于它能够在自觉地认识客...\', \'position\': None}]', '\n{\n  \"meta\": {\n    \"name\": \"预测\",\n    \"author\": \"AI生成\",\n    \"version\": \"1.0\"\n  },\n  \"format\": \"node_tree\",\n  \"data\": {\n    \"id\": \"1\",\n    \"topic\": \"机器学习与预测\",\n    \"children\": [\n      {\n        \"id\": \"1-1\",\n        \"topic\": \"预测的本质\",\n        \"children\": [\n          {\n            \"id\": \"1-1-1\",\n            \"topic\": \"通过历史数据挖掘规律\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-1-2\",\n            \"topic\": \"总结、分类或预测未来数值\",\n            \"children\": []\n          }\n        ]\n      },\n      {\n        \"id\": \"1-2\",\n        \"topic\": \"预测的应用场景\",\n        \"children\": [\n          {\n            \"id\": \"1-2-1\",\n            \"topic\": \"分类问题\",\n            \"children\": [\n              {\n                \"id\": \"1-2-1-1\",\n                \"topic\": \"是否有购买意向\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-2-1-2\",\n                \"topic\": \"是否为优质客户\",\n                \"children\": []\n              }\n            ]\n          },\n          {\n            \"id\": \"1-2-2\",\n            \"topic\": \"数值预测\",\n            \"children\": [\n              {\n                \"id\": \"1-2-2-1\",\n                \"topic\": \"销售额预测\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-2-2-2\",\n                \"topic\": \"产品偏好预测\",\n                \"children\": []\n              }\n            ]\n          },\n          {\n            \"id\": \"1-2-3\",\n            \"topic\": \"关联度分析\",\n            \"children\": [\n              {\n                \"id\": \"1-2-3-1\",\n                \"topic\": \"用户同时购买A和B的概率\",\n                \"children\": []\n              }\n            ]\n          },\n          {\n            \"id\": \"1-2-4\",\n            \"topic\": \"图像识别\",\n            \"children\": [\n              {\n                \"id\": \"1-2-4-1\",\n                \"topic\": \"预测物体类别或概率\",\n                \"children\": []\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"id\": \"1-3\",\n        \"topic\": \"实现预测的两种方法\",\n        \"children\": [\n          {\n            \"id\": \"1-3-1\",\n            \"topic\": \"数学与统计学方法\",\n            \"children\": [\n              {\n                \"id\": \"1-3-1-1\",\n                \"topic\": \"最小二乘法\",\n                \"children\": [\n                  {\n                    \"id\": \"1-3-1-1-1\",\n                    \"topic\": \"一元线性回归\",\n                    \"children\": []\n                  }\n                ]\n              }\n            ]\n          },\n          {\n            \"id\": \"1-3-2\",\n            \"topic\": \"机器学习方法\",\n            \"children\": [\n              {\n                \"id\": \"1-3-2-1\",\n                \"topic\": \"处理复杂方程\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-3-2-2\",\n                \"topic\": \"多元线性回归\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-3-2-3\",\n                \"topic\": \"神经网络\",\n                \"children\": []\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"id\": \"1-4\",\n        \"topic\": \"数学示例：鸡兔同笼问题\",\n        \"children\": [\n          {\n            \"id\": \"1-4-1\",\n            \"topic\": \"已知条件\",\n            \"children\": [\n              {\n                \"id\": \"1-4-1-1\",\n                \"topic\": \"头数：35\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-4-1-2\",\n                \"topic\": \"脚数：94\",\n                \"children\": []\n              }\n            ]\n          },\n          {\n            \"id\": \"1-4-2\",\n            \"topic\": \"解法\",\n            \"children\": [\n              {\n                \"id\": \"1-4-2-1\",\n                \"topic\": \"建立方程组\",\n                \"children\": [\n                  {\n                    \"id\": \"1-4-2-1-1\",\n                    \"topic\": \"x + y = 35\",\n                    \"children\": []\n                  },\n                  {\n                    \"id\": \"1-4-2-1-2\",\n                    \"topic\": \"2x + 4y = 94\",\n                    \"children\": []\n                  }\n                ]\n              },\n              {\n                \"id\": \"1-4-2-2\",\n                \"topic\": \"求解过程\",\n                \"children\": [\n                  {\n                    \"id\": \"1-4-2-2-1\",\n                    \"topic\": \"化简得 x + 3y = 59\",\n                    \"children\": []\n                  },\n                  {\n                    \"id\": \"1-4-2-2-2\",\n                    \"topic\": \"代入求解 x 和 y\",\n                    \"children\": []\n                  }\n                ]\n              }\n            ]\n          }\n        ]\n      }\n    ]\n  }\n}\n', '\n{\n  \"choices\": [\n    {\n      \"question\": \"最小二乘法主要用于解决以下哪种问题？\",\n      \"options\": {\n        \"A\": \"分类问题\",\n        \"B\": \"回归问题\",\n        \"C\": \"聚类问题\",\n        \"D\": \"降维问题\"\n      },\n      \"answer\": \"B\"\n    },\n    {\n      \"question\": \"在一元线性回归中，我们通过最小二乘法主要求解的是哪两个参数？\",\n      \"options\": {\n        \"A\": \"a和b\",\n        \"B\": \"x和y\",\n        \"C\": \"σ和μ\",\n        \"D\": \"w和b\"\n      },\n      \"answer\": \"A\"\n    },\n    {\n      \"question\": \"在机器学习中，预测的主要目的是什么？\",\n      \"options\": {\n        \"A\": \"从历史数据中提取规律并进行未来推断\",\n        \"B\": \"仅对已有数据进行分类\",\n        \"C\": \"生成新的数据\",\n        \"D\": \"单纯优化计算效率\"\n      },\n      \"answer\": \"A\"\n    },\n    {\n      \"question\": \"鸡兔同笼问题可以通过哪种方法求解？（多选）\",\n      \"options\": {\n        \"A\": \"数学公式法\",\n        \"B\": \"穷举法\",\n        \"C\": \"机器学习模型\",\n        \"D\": \"深度神经网络\"\n      },\n      \"answer\": \"AB\"\n    },\n    {\n      \"question\": \"多元线性回归相较于一元线性回归的区别在于：\",\n      \"options\": {\n        \"A\": \"只有一个自变量\",\n        \"B\": \"有多个自变量\",\n        \"C\": \"无法使用最小二乘法\",\n        \"D\": \"必须使用神经网络求解\"\n      },\n      \"answer\": \"B\"\n    },\n    {\n      \"question\": \"以下哪个领域可以被归结为预测问题？\",\n      \"options\": {\n        \"A\": \"图像识别\",\n        \"B\": \"文本分类\",\n        \"C\": \"用户行为分析\",\n        \"D\": \"以上全部\"\n      },\n      \"answer\": \"D\"\n    },\n    {\n      \"question\": \"在鸡兔同笼问题中，若头数为35，脚数为94，则兔子的数量是多少？\",\n      \"options\": {\n        \"A\": \"12\",\n        \"B\": \"23\",\n        \"C\": \"35\",\n        \"D\": \"94\"\n      },\n      \"answer\": \"B\"\n    },\n    {\n      \"question\": \"机器学习中的函数拟合与传统数学方法相比，优势在于：\",\n      \"options\": {\n        \"A\": \"更适合处理复杂的非线性关系\",\n        \"B\": \"计算速度更快\",\n        \"C\": \"完全不需要人工干预\",\n        \"D\": \"无需数据即可完成预测\"\n      },\n      \"answer\": \"A\"\n    }\n  ],\n  \"qas\": [\n    {\n      \"question\": \"请简述最小二乘法的基本原理及其应用场景。\",\n      \"answer\": \"最小二乘法是一种用于寻找最佳拟合直线或曲线的方法，其基本原理是通过最小化误差的平方和来确定模型参数。它广泛应用于回归分析中，用于预测连续型变量的值。例如，在一元线性回归中，我们通过最小二乘法求解斜率和截距，从而得到最佳拟合直线。\"\n    },\n    {\n      \"question\": \"在实际应用中，如何判断一个问题是适合用机器学习方法还是传统数学方法解决？\",\n      \"answer\": \"如果问题是简单的线性关系或已知明确的数学公式，则传统数学方法更为高效；但如果问题涉及复杂的非线性关系、高维数据或大量未知参数，则机器学习方法更具优势。此外，当数据量较大且需要自动化处理时，机器学习也更适用。\"\n    },\n    {\n      \"question\": \"结合鸡兔同笼问题，说明数学公式法和机器学习方法在解决问题时的异同点。\",\n      \"answer\": \"数学公式法直接利用已知条件建立方程组并求解，过程清晰且结果精确；而机器学习方法则可能通过训练模型（如回归模型）来拟合输入输出关系，虽然也能得出正确答案，但通常需要更多数据和计算资源。两者的主要区别在于，数学公式法依赖于明确的规则，而机器学习方法更注重从数据中自动学习规律。\"\n    }\n  ]\n}\n', '2025-06-07 00:11:41');
INSERT INTO `videos` VALUES ('5', '旋转与灰度化与二值化', '20250607_002019_929436.mp4', '195', '计算机视觉', '好我们继续往后看哈那个图片的基本操作啊这儿呢给大家说了一下关于这个说放的问题那我们继续来看哈那我呢这个因为图像数据读出来的是一个nd array的数组对吧那所以呢我们其实也可以尝试给它换一个方向哎 别说哈 这个叫这个旋转 是吧旋转怎么做呢 那非常简单 因为读出来的本身就是一个什么就是一个这个number pi的数组 所以我们可以image这个旋转的单词怎么写的旋转rotate对吧好那么就root那等于number pi点怎么number pi本身类置了一个rootroot90就表示旋转90度然后这样呢我们旋转90度那宽和高是不是就正好交叉了然后我们再来修image root这样呢我们看到的图片那就是旋转以后的样子然后旋转以后的样子那这就是旋转过后的样子当然我还可以旋转旋转90度我们看历史针还顺时针正常的图片这张图片可能看起来没那么方便我们换一张图换涡流学院换logo这个图片那看起来就方便了logo.jpg那我们看到啊正常来说是怎么样的正常来说是这个样子的然后现在旋转了以后变成了这个样子这顺势针还逆势针logo在这儿到下边了啊那么我们呢它是不是应该这么旋转的他说应该是这样旋转的logo在下方吗如果他这样旋转的话如果他这样旋转的话logo是不是在上方对吧所以他这样旋转那这个旋转是什么是我们的一个逆时针旋转的逆时针旋转好如果我要我想让他的logo在上方我还得怎么我还得呢旋转270度那rotate root90这个叫旋转90度那么这边默认有个k等于1代表这个旋转的次数所以我可以给它旋转270度的话这叫我们叫逆时针旋转90度180度那顺着还是逆的我做了', '<div>\n    <h3>课程笔记：图像旋转操作</h3>\n    <p>本节课主要讲解了如何对图像进行旋转操作，具体步骤和方法如下：</p>\n    <ul>\n        <li>图像数据读取后会以ndarray数组的形式存储。</li>\n        <li>可以利用<code>rotate</code>函数实现图像的旋转功能。</li>\n        <li><code>rotate</code>函数的基本用法为：<code>rotate(k=1)</code>，其中参数<code>k</code>表示旋转次数，默认每次旋转90度。</li>\n        <li>旋转方向：\n            <ul>\n                <li><code>k=1</code> 表示顺时针旋转90度。</li>\n                <li><code>k=2</code> 表示顺时针旋转180度。</li>\n                <li><code>k=3</code> 表示顺时针旋转270度（等同于逆时针旋转90度）。</li>\n                <li><code>k=4</code> 表示旋转360度（回到原位）。</li>\n            </ul>\n        </li>\n        <li>通过调整<code>k</code>的值，可以控制图像的旋转角度，从而满足不同的需求。例如，如果希望将图片中的Logo从下方移动到上方，可以通过设置<code>k=3</code>（即旋转270度，逆时针旋转90度）来实现。</li>\n        <li>实际操作中，可以选择不同图片进行测试，观察旋转后的效果，以便更好地理解旋转原理。</li>\n    </ul>\n    <p>总结：通过本节学习，我们掌握了如何使用<code>rotate</code>函数对图像进行旋转操作，并了解了旋转角度与参数<code>k</code>的关系。</p>\n</div>', '图像旋转', '[{\'link\': \'https://m.sohu.com/a/861960293_121964601\', \'title\': \'如何将图片旋转任意角度？五个方法轻松旋转\', \'content\': \'如何将图片旋转任意角度？五个方法轻松旋转\\n图片旋转任意角度方法一：使用“星优图片处理大师”软件步骤1，在电脑上将“星优图片处理大师”软件下载到电脑上并进行安装，安装好之后既可以开始操作了，软件左侧为功能区域，请你找到并选择【批量旋转】功能。步骤2，随后点击软件上的【添加文件】按键，将需要旋转的图片添加到软件里，还可以直接用鼠标将图片拖入软件中进行添加，并且软件支持图片批量处理。步骤3，在软件右侧设置图片旋转角度（正值图片向右旋转，负值图片向左旋转），大家根据自己的需要进行设置。软件中间是预览图，这样就可以对旋转效果进行检查。步骤4，设置完成后点击右下角红色按键启动软件，软件开始按照设置的数字旋转图片，处理完成后软件会自动打开输出文件夹，旋转后的图片就保存在这里。步骤5，从下图可以看到，软件成功帮助我们将3张图片进行了旋转，证明方法使用正确。\', \'snippet\': \'图片旋转任意角度方法一：使用“星优图片处理大师”软件步骤1，在电脑上将“星优图片处理大师”软件下载到电脑上并进行安装，安装好之后既可以开始操作了，软件左侧为功能区域，请你找到并选择【批量旋转】功能。步骤2，随后点击软件上的【添加文件】按键，将需要旋转的图片添加到软件里，还可以直接用鼠标将图片拖入软件中进行添加，并且软件支持图片批量处理。步骤3，在软件右侧设置图片旋转角度（正值图片向右旋转，负值图片向左旋转），大家根据自己的需要进行设置。软件中间是预览图，这样就可以对旋转效果进行检查。步骤4，设置完成后点击右下角红色按键启动软件，软件开始按照设置的数字旋转图片，处理完成后软件会自动打开输出文件夹，旋转后的图片就保存在这里。步骤5，从下图可以看到，软件成功帮助我们将3张图片进行了旋转，证明方法使用正确。\', \'position\': None}, {\'link\': \'http://m.2265.com/k/tupianxuanzhuan\', \'title\': \'图片旋转软件大全-图片旋转工具-图片旋转软件手机版下载\', \'content\': \'图片旋转软件大全-图片旋转工具-图片旋转软件手机版下载\\n来2265找图片旋转软件免费下载专题,这里汇集了全网各种不同类型的图片旋转软件,为用户们提供免费下载,在这里各种不同类型图片...\', \'snippet\': \'来2265找图片旋转软件免费下载专题,这里汇集了全网各种不同类型的图片旋转软件,为用户们提供免费下载,在这里各种不同类型图片...\', \'position\': None}, {\'link\': \'https://baijiahao.baidu.com/s?id=1825536887301473096\', \'title\': \'怎样才能轻松实现图片批量的垂直（180°）旋转呢？分享4个方法\', \'content\': \'怎样才能轻松实现图片批量的垂直（180°）旋转呢？分享4个方法\\n不仅操作简单，还可以任意角度旋转，小编介绍的以下几种方法可以实现图片的批量任选旋转！有需要的朋友一起看看吧！第一个方法...\', \'snippet\': \'不仅操作简单，还可以任意角度旋转，小编介绍的以下几种方法可以实现图片的批量任选旋转！有需要的朋友一起看看吧！第一个方法...\', \'position\': None}, {\'link\': \'https://www.gaitubao.com/xuanzhuan/\', \'title\': \'在线旋转图片方向工具\', \'content\': \'在线旋转图片方向工具\\n本工具可以对图片进行顺逆时针、90/180度、生成镜像等旋转操作，也可手动输入指定角度 如果你的图片使用本工具无法达到想要的效果（如非90度、180度旋转、填充背景等）可以使用专业软件修改...\', \'snippet\': \'本工具可以对图片进行顺逆时针、90/180度、生成镜像等旋转操作，也可手动输入指定角度 如果你的图片使用本工具无法达到想要的效果（如非90度、180度旋转、填充背景等）可以使用专业软件修改...\', \'position\': None}]', '\n{\n  \"meta\": {\n    \"name\": \"图像旋转\",\n    \"author\": \"AI生成\",\n    \"version\": \"1.0\"\n  },\n  \"format\": \"node_tree\",\n  \"data\": {\n    \"id\": \"1\",\n    \"topic\": \"图像的基本操作：旋转\",\n    \"children\": [\n      {\n        \"id\": \"1-1\",\n        \"topic\": \"图像数据的表示\",\n        \"children\": [\n          {\n            \"id\": \"1-1-1\",\n            \"topic\": \"图像读取为ndarray数组\",\n            \"children\": []\n          }\n        ]\n      },\n      {\n        \"id\": \"1-2\",\n        \"topic\": \"旋转的基本概念\",\n        \"children\": [\n          {\n            \"id\": \"1-2-1\",\n            \"topic\": \"旋转通过rotate函数实现\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-2-2\",\n            \"topic\": \"rotate参数说明\",\n            \"children\": [\n              {\n                \"id\": \"1-2-2-1\",\n                \"topic\": \"k=1表示顺时针旋转90度\",\n                \"children\": []\n              },\n              {\n                \"id\": \"1-2-2-2\",\n                \"topic\": \"k=3表示顺时针旋转270度（等同于逆时针90度）\",\n                \"children\": []\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"id\": \"1-3\",\n        \"topic\": \"实际案例：涡流学院Logo旋转\",\n        \"children\": [\n          {\n            \"id\": \"1-3-1\",\n            \"topic\": \"原始Logo方向\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-3-2\",\n            \"topic\": \"顺时针旋转90度后的效果\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-3-3\",\n            \"topic\": \"逆时针旋转90度（旋转270度）后的效果\",\n            \"children\": []\n          }\n        ]\n      },\n      {\n        \"id\": \"1-4\",\n        \"topic\": \"总结\",\n        \"children\": [\n          {\n            \"id\": \"1-4-1\",\n            \"topic\": \"旋转角度与方向的关系\",\n            \"children\": []\n          },\n          {\n            \"id\": \"1-4-2\",\n            \"topic\": \"根据需求调整旋转参数\",\n            \"children\": []\n          }\n        ]\n      }\n    ]\n  }\n}\n', '\n{\n    \"choices\": [\n        {\n            \"question\": \"在图像处理中，使用NumPy数组表示图像时，如何实现图像的旋转？\",\n            \"options\": {\n                \"A\": \"通过改变数组的形状（shape）\",\n                \"B\": \"通过调用NumPy内置的rotate函数\",\n                \"C\": \"通过调整数组的索引顺序\",\n                \"D\": \"直接修改数组中的像素值\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"如果要将一张图像逆时针旋转90度，以下哪个选项是正确的操作方法？\",\n            \"options\": {\n                \"A\": \"rotate(image, 90)\",\n                \"B\": \"rotate(image, -90)\",\n                \"C\": \"rotate(image, 270)\",\n                \"D\": \"rotate(image, k=3)\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"NumPy中的`np.rot90`函数默认参数k=1时，表示图像如何旋转？\",\n            \"options\": {\n                \"A\": \"顺时针旋转90度\",\n                \"B\": \"逆时针旋转90度\",\n                \"C\": \"顺时针旋转270度\",\n                \"D\": \"不旋转\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"在图像处理中，旋转图像的本质是什么？\",\n            \"options\": {\n                \"A\": \"改变图像的颜色通道\",\n                \"B\": \"改变图像像素点的排列方式\",\n                \"C\": \"增加或减少图像的分辨率\",\n                \"D\": \"压缩或拉伸图像的尺寸\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"如果需要将图像顺时针旋转270度，等价于以下哪种操作？\",\n            \"options\": {\n                \"A\": \"逆时针旋转90度\",\n                \"B\": \"逆时针旋转180度\",\n                \"C\": \"顺时针旋转90度\",\n                \"D\": \"逆时针旋转270度\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"在NumPy中，执行`np.rot90(image, k=2)`后，图像会发生什么变化？\",\n            \"options\": {\n                \"A\": \"顺时针旋转180度\",\n                \"B\": \"逆时针旋转180度\",\n                \"C\": \"顺时针旋转90度\",\n                \"D\": \"逆时针旋转90度\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"假设图像的高度为H，宽度为W，旋转90度后，新的高度和宽度分别是多少？\",\n            \"options\": {\n                \"A\": \"高度仍为H，宽度仍为W\",\n                \"B\": \"高度为W，宽度为H\",\n                \"C\": \"高度为H/2，宽度为W/2\",\n                \"D\": \"高度为2H，宽度为2W\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"在NumPy中，`np.rot90`函数的参数k表示什么？\",\n            \"options\": {\n                \"A\": \"旋转的角度\",\n                \"B\": \"旋转的方向\",\n                \"C\": \"旋转的次数\",\n                \"D\": \"旋转的速度\"\n            },\n            \"answer\": \"C\"\n        }\n    ],\n    \"qas\": [\n        {\n            \"question\": \"请解释图像旋转过程中，为什么需要调整像素点的排列顺序？\",\n            \"answer\": \"图像旋转的本质是对像素点重新排列。当图像被旋转时，原始像素点的位置会发生变化，因此需要根据旋转角度重新计算每个像素点的新位置，从而生成旋转后的图像。\"\n        },\n        {\n            \"question\": \"在NumPy中，如何实现图像的顺时针旋转90度？请写出具体的操作步骤。\",\n            \"answer\": \"在NumPy中，可以通过`np.rot90(image, k=-1)`实现图像的顺时针旋转90度。其中，参数`k=-1`表示顺时针旋转一次（即90度）。\"\n        },\n        {\n            \"question\": \"如果需要将一张图像先顺时针旋转90度，再逆时针旋转90度，最终图像会有什么变化？\",\n            \"answer\": \"最终图像将恢复到原始状态。因为顺时针旋转90度相当于逆时针旋转270度，而逆时针旋转90度恰好抵消了之前的旋转操作，因此图像回到初始状态。\"\n        }\n    ]\n}\n', '2025-06-07 00:23:33');
INSERT INTO `videos` VALUES ('6', '向量数据库与Chroma', '20250607_002515_074011.mp4', '312', '机器学习', '好 那我们今天的内容呢是两个啊 第一个先给大家讲一下向量数据库Chroma的一个应用呃 然后呢 我们再基于LongChain加Chroma再加上前后端交互啊 咱们来实现一个在线智能客服的这么一个项目啊 这个呢 是项目的这么一个界面啊 那么这种智能客服呢它就不是通用的一个这个问答了而是针对一个特定的企业特定的组织它专有的一些指使来回答问题对吧比方说大家可以看到那我呢问这个客服问的都是跟温流学院的培训课程或者说这个公司的一些情况有关的这么一些内容那这就是属于我们的一个向量数据库这么一个应用场景在线智能客服这也是比较常见的应用场景也是我们AI呢目前应用的比较成熟的一个场景我给大家去讲一讲该怎么来做好吧那我们先来聊一聊关于Chroma前面呢我们也给大家提到了项量数据库都知道咋回事所以基本的这些情况呢我就不再过多的去介绍了核心来说呢无非就是将我们的知识或者说我们的文档加载了以后项量化那向量的核心是不是就磁迁入当然你可以用任何的磁迁入模型这儿呢关于磁迁入模型我稍微多说一句我们前边讲自然源处理的时候是给大家讲过怎么来训练这个磁向量的对吧那么同时呢我们已经训练越训练好的这模型那么相当于这个向量呢已经都优化好了事实上这也是我们这个文本计算的最核心的那个这个数据了比方说我们基于这个签问啊基于呃open eye啊gpt或者基于这个bert或者基于各种各样的大模型那好无所谓了那么相当于他们是初始路是不是都是持签路对吧那所以然后在不停的迭代训练的过程当中那么这个向量呢相当于已经是按照最优解来进行训练的所以呢那么我们呢现在啊相当于你就要向量化的话是不是你就需要找一个成熟的模型来进行直迁入这前面我们也有介绍到那么这个模型呢那我们知道在神经网络里边那每一层模型我们都可以单独拼出来那相当于这模型比方说我们使用这个Olama的embedding然后针对着我们用的是这个千万2.5.7B的这个模型那如果你用这个模型当我们在线电话的那些哈这个在线提供的那些APF比方说通议哈当然也都有哈那这呢当我呢说到这儿哈我稍微的再给大家提供一下因为我们前面做实验在线的那个我主要给大家对接的是什么通议签问和定性对吧事实上呢还有一个叫这个字谱啊字谱AI一个模特质朴AI也不错大家如果有心血可以去测试一下看看效果然后质朴AI价格也比较便宜跟低谱这个差不多对吧你看我充了20块钱到现在都没用多少对吧用的很少但因为平时做实验偏多一点还是用的欧拉玛而已用这个在线的用的没有那么多那么所以呢大家也可以来去这个质朴上边去注册一个账号来体验一下那字谱这边的开发文档呢也是相对还比较全面的那么用字谱有个好处就是它既提供了这个文本的生成又提供了这个多模态的视觉识笔同时呢它也具备文生图的能力CogView和文生视频的CogVideo当然还包括我们的一些磁迁入的向量的一个运算那么这边呢就是给大家说一下那他同样的支持sdkpython的stk和java的sdk他都是支持的提供python和java同样的也支持http这个调用也支持http协议的调用那这些呢当然常过来说都是ok的我们通议签问同样也可以使用desic scope同样的也可以使用http协议是吧直接发请求的方式调用都没有问题那BIGMO那个字谱如果它的官网叫BIGMO的而已这个字谱AI呢模型呢好评度也还不错是吧关键呢对我们来说一方面接口也比较简单另外呢它支持的模型跟通议签问一样也比较多对吧支持视觉当然签问的系列同样也支持通议签问也支持文本然后文本视觉VL以及文身图', '<h2>课程笔记：基于Chroma向量数据库和LongChain实现在线智能客服</h2>\n\n<h3>一、课程内容概述</h3>\n<p>本节课主要讲解了如何利用向量数据库Chroma以及LongChain框架，结合前后端交互，构建一个针对特定企业或组织的在线智能客服系统。这种智能客服能够根据企业的专有知识库回答用户的问题，是目前AI技术应用较为成熟的一个场景。</p>\n\n<h3>二、核心知识点</h3>\n\n<h4>1. Chroma向量数据库的应用</h4>\n<ul>\n    <li>Chroma是一个用于存储和检索高维向量的数据库，适用于文本、图像等数据的相似性搜索。</li>\n    <li>向量数据库的核心功能是将文档或知识转化为向量形式，并通过嵌入模型（Embedding Model）进行优化。</li>\n    <li>嵌入模型的选择非常重要，常见的模型包括OpenAI的GPT系列、BERT，以及Olama等。</li>\n    <li>这些模型通过不断迭代训练，生成的向量能够更好地表示文本的语义信息。</li>\n</ul>\n\n<h4>2. 嵌入模型与选择</h4>\n<ul>\n    <li>嵌入模型的作用是将文本转换为高维向量，便于后续计算和检索。</li>\n    <li>推荐的嵌入模型包括：\n        <ul>\n            <li>Olama的embedding（如千万2.5.7B模型）</li>\n            <li>通义千问（Qwen）</li>\n            <li>字谱AI（ZiPu AI）</li>\n        </ul>\n    </li>\n    <li>字谱AI的特点：\n        <ul>\n            <li>支持文本生成、多模态视觉识别、文生图（CogView）、文生视频（CogVideo）等功能。</li>\n            <li>提供Python和Java SDK，同时支持HTTP协议调用。</li>\n            <li>接口简单，价格相对低廉。</li>\n        </ul>\n    </li>\n</ul>\n\n<h4>3. 在线智能客服的实现步骤</h4>\n<ul>\n    <li>加载知识文档并将其转化为向量形式。</li>\n    <li>使用Chroma存储向量数据。</li>\n    <li>通过LongChain框架整合前后端交互逻辑。</li>\n    <li>前端接收用户问题，后端调用嵌入模型计算相似度并返回最相关答案。</li>\n</ul>\n\n<h4>4. 推荐工具与资源</h4>\n<ul>\n    <li>通义千问（Qwen）：适合中文场景，支持多种API调用方式。</li>\n    <li>字谱AI（ZiPu AI）：支持多模态任务，开发文档全面。</li>\n    <li>建议尝试注册字谱AI账号，体验其文本生成、视觉识别等功能。</li>\n</ul>\n\n<h3>三、总结</h3>\n<p>本节课重点介绍了如何利用Chroma向量数据库和LongChain框架构建在线智能客服系统。通过选择合适的嵌入模型（如Olama、通义千问、字谱AI），可以高效地将企业知识转化为向量形式，并实现精准的问答匹配。此外，还推荐了字谱AI作为备选工具，因其功能丰富且价格实惠，值得进一步探索。</p>', '向量数据库与智能客服', '[{\'link\': \'https://baike.baidu.com/item/%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93/63110709\', \'title\': \'向量数据库\', \'content\': \'向量数据库\\n向量数据库是专门用来存储和查询向量的数据库，其存储的向量来自于对文本、语音、图像、视频等的向量化。与传统数据库相比，向量数据库可以处理更多非结构化数据（比如图像和音频）。在机器学习和深度学习中，数据通常以向量形式表示。\', \'snippet\': \'向量数据库是专门用来存储和查询向量的数据库，其存储的向量来自于对文本、语音、图像、视频等的向量化。与传统数据库相比，向量数据库可以处理更多非结构化数据（比如图像和音频）。在机器学习和深度学习中，数据通常以向量形式表示。\', \'position\': None}, {\'link\': \'https://baijiahao.baidu.com/s?id=1796653068244076418\', \'title\': \'智能客服功能是如何实现的？\', \'content\': \'智能客服功能是如何实现的？\\n我们将深入探讨智能客服功能是如何实现的，包括其背后的技术原理、应用场景以及未来发展趋势。1、智能客服功能实现的基础是自然语言处理（NLP）技术。自然语言处理是一种让计算机理解和处理人类语言的技术，它涉及到语言学、计算机科学和人工智能等多个领域。在智能客服系统中，NLP技术被用于解析用户的输入，识别用户的意图和需求，从而为用户提供准确的回答和解决方案。2、智能客服功能还需要依赖知识图谱和机器学习等技术。知识图谱是一种用于表示实体之间关系的图形化数据结构，它可以帮助智能客服系统快速定位和获取相关信息。而机器学习技术则可以让智能客服系统从大量的数据中学习并自我优化，不断提高其回答问题的准确性和效率。\', \'snippet\': \'我们将深入探讨智能客服功能是如何实现的，包括其背后的技术原理、应用场景以及未来发展趋势。1、智能客服功能实现的基础是自然语言处理（NLP）技术。自然语言处理是一种让计算机理解和处理人类语言的技术，它涉及到语言学、计算机科学和人工智能等多个领域。在智能客服系统中，NLP技术被用于解析用户的输入，识别用户的意图和需求，从而为用户提供准确的回答和解决方案。2、智能客服功能还需要依赖知识图谱和机器学习等技术。知识图谱是一种用于表示实体之间关系的图形化数据结构，它可以帮助智能客服系统快速定位和获取相关信息。而机器学习技术则可以让智能客服系统从大量的数据中学习并自我优化，不断提高其回答问题的准确性和效率。\', \'position\': None}, {\'link\': \'https://m.blog.csdn.net/u013172930/article/details/147399635\', \'title\': \'什么是 向量数据库（Vector Database）\', \'content\': \'什么是 向量数据库（Vector Database）\\n向量数据库（Vector Database）是一种专门设计用于存储、索引和管理高维向量数据的数据库系统。这些向量通常是机器学习模型（如深度学习模型）生成的嵌入（embeddings），用于表示文本、图像、音频等数据的语义特征。向量数据库的核心目标是高效地支持向量相似性搜索（Similarity Search），\', \'snippet\': \'向量数据库（Vector Database）是一种专门设计用于存储、索引和管理高维向量数据的数据库系统。这些向量通常是机器学习模型（如深度学习模型）生成的嵌入（embeddings），用于表示文本、图像、音频等数据的语义特征。向量数据库的核心目标是高效地支持向量相似性搜索（Similarity Search），\', \'position\': None}, {\'link\': \'https://www.hollycrm.com/innews/6257.html\', \'title\': \'如何实现24小时客服在线系统？智能客服技术应用\', \'content\': \'如何实现24小时客服在线系统？智能客服技术应用\\n一、智能客服技术应用。自然语言处理与机器学习：  二、多渠道接入与整合。\', \'snippet\': \'一、智能客服技术应用。自然语言处理与机器学习：  二、多渠道接入与整合。\', \'position\': None}]', '\n{\n  \"meta\": {\n    \"name\": \"向量数据库与智能客服\",\n    \"author\": \"AI生成\",\n    \"version\": \"1.0\"\n  },\n  \"format\": \"node_tree\",\n  \"data\": {\n    \"id\": \"1\",\n    \"topic\": \"向量数据库与智能客服项目\",\n    \"children\": [\n      {\n        \"id\": \"1-1\",\n        \"topic\": \"项目概述\",\n        \"children\": [\n          {\n            \"id\": \"1-1-1\",\n            \"topic\": \"目标：实现在线智能客服\"\n          },\n          {\n            \"id\": \"1-1-2\",\n            \"topic\": \"特点：针对特定企业或组织的专有知识问答\"\n          },\n          {\n            \"id\": \"1-1-3\",\n            \"topic\": \"应用场景：常见且成熟的AI应用\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-2\",\n        \"topic\": \"技术栈\",\n        \"children\": [\n          {\n            \"id\": \"1-2-1\",\n            \"topic\": \"向量数据库：Chroma\"\n          },\n          {\n            \"id\": \"1-2-2\",\n            \"topic\": \"框架：LangChain\"\n          },\n          {\n            \"id\": \"1-2-3\",\n            \"topic\": \"前后端交互\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-3\",\n        \"topic\": \"向量数据库的核心：向量化\",\n        \"children\": [\n          {\n            \"id\": \"1-3-1\",\n            \"topic\": \"知识或文档的加载与向量化\"\n          },\n          {\n            \"id\": \"1-3-2\",\n            \"topic\": \"向量优化：通过预训练模型实现\"\n          },\n          {\n            \"id\": \"1-3-3\",\n            \"topic\": \"常用模型：OpenAI GPT、BERT等\"\n          }\n        ]\n      },\n      {\n        \"id\": \"1-4\",\n        \"topic\": \"推荐的Embedding模型与服务\",\n        \"children\": [\n          {\n            \"id\": \"1-4-1\",\n            \"topic\": \"Olama Embedding (千万2.5.7B模型)\"\n          },\n          {\n            \"id\": \"1-4-2\",\n            \"topic\": \"通义千问与定制化服务\"\n          },\n          {\n            \"id\": \"1-4-3\",\n            \"topic\": \"字谱AI\",\n            \"children\": [\n              {\n                \"id\": \"1-4-3-1\",\n                \"topic\": \"优点：价格便宜，接口简单\"\n              },\n              {\n                \"id\": \"1-4-3-2\",\n                \"topic\": \"支持多模态任务：文本生成、文生图、文生视频\"\n              },\n              {\n                \"id\": \"1-4-3-3\",\n                \"topic\": \"开发文档全面，支持Python和Java SDK\"\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"id\": \"1-5\",\n        \"topic\": \"调用方式\",\n        \"children\": [\n          {\n            \"id\": \"1-5-1\",\n            \"topic\": \"HTTP协议调用\"\n          },\n          {\n            \"id\": \"1-5-2\",\n            \"topic\": \"SDK支持：Python、Java\"\n          }\n        ]\n      }\n    ]\n  }\n}\n', '\n{\n    \"choices\": [\n        {\n            \"question\": \"向量数据库Chroma的主要应用场景是什么？\",\n            \"options\": {\n                \"A\": \"通用问答系统\",\n                \"B\": \"在线智能客服\",\n                \"C\": \"图像识别\",\n                \"D\": \"语音合成\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"在向量化过程中，以下哪种模型可以用于生成向量？\",\n            \"options\": {\n                \"A\": \"BERT\",\n                \"B\": \"GPT\",\n                \"C\": \"OpenAI Embedding\",\n                \"D\": \"以上皆可\"\n            },\n            \"answer\": \"D\"\n        },\n        {\n            \"question\": \"以下哪项不是质朴AI（Zhipu AI）提供的功能？\",\n            \"options\": {\n                \"A\": \"文本生成\",\n                \"B\": \"多模态视觉识别\",\n                \"C\": \"文生图\",\n                \"D\": \"硬件加速\"\n            },\n            \"answer\": \"D\"\n        },\n        {\n            \"question\": \"关于Olama Embedding模型，以下描述正确的是？\",\n            \"options\": {\n                \"A\": \"只能用于英文文本\",\n                \"B\": \"基于千万2.5.7B模型训练\",\n                \"C\": \"不支持API调用\",\n                \"D\": \"无法用于在线客服\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"通义千问（Qwen）和质朴AI相比，以下哪项是正确的？\",\n            \"options\": {\n                \"A\": \"通义千问价格更便宜\",\n                \"B\": \"质朴AI接口更复杂\",\n                \"C\": \"两者都支持HTTP协议调用\",\n                \"D\": \"质朴AI不支持Python SDK\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"CogView和CogVideo分别对应的功能是？\",\n            \"options\": {\n                \"A\": \"文本生成和语音合成\",\n                \"B\": \"文生图和文生视频\",\n                \"C\": \"图像识别和语音识别\",\n                \"D\": \"自然语言处理和机器翻译\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"以下哪种方式不能用于调用质朴AI的服务？\",\n            \"options\": {\n                \"A\": \"Python SDK\",\n                \"B\": \"Java SDK\",\n                \"C\": \"HTTP请求\",\n                \"D\": \"直接编译源码\"\n            },\n            \"answer\": \"D\"\n        },\n        {\n            \"question\": \"在神经网络中，每一层模型都可以单独拼接出来，这种说法是否正确？\",\n            \"options\": {\n                \"A\": \"正确\",\n                \"B\": \"错误\",\n                \"C\": \"视情况而定\",\n                \"D\": \"无法判断\"\n            },\n            \"answer\": \"A\"\n        }\n    ],\n    \"qas\": [\n        {\n            \"question\": \"向量数据库Chroma的核心作用是什么？请简要说明。\",\n            \"answer\": \"向量数据库Chroma的核心作用是将知识或文档进行向量化存储，并通过相似度搜索实现高效的知识检索。这对于构建在线智能客服等场景非常关键。\"\n        },\n        {\n            \"question\": \"质朴AI（Zhipu AI）有哪些优势？请列举至少两点。\",\n            \"answer\": \"1. 提供多种能力，包括文本生成、多模态视觉识别和文生图；2. 接口简单且支持多种编程语言（如Python、Java）及HTTP协议调用；3. 价格相对较低，适合实验和小规模应用。\"\n        },\n        {\n            \"question\": \"如何利用Chroma和LongChain构建一个在线智能客服系统？请简述步骤。\",\n            \"answer\": \"1. 使用Chroma加载并向量化企业专属文档或知识库；2. 利用LongChain框架整合向量数据库与大语言模型（如通义千问）；3. 开发前后端交互界面，允许用户输入问题并获取智能回答；4. 部署系统并优化性能以适应实际需求。\"\n        }\n    ]\n}\n', '2025-06-07 00:32:08');
INSERT INTO `videos` VALUES ('7', '神经网络机制与激活函数', '20250608_235418_002996.mp4', '338', '神经网络', '好 那么接下来呢 来快速看一看 这个神经网络的一些细节的问题神经网络构成神经网络最核心的就这个神经元了 就这个神经元那么这是第一个点 神经元神经元是用于接收输入信号并产生输出信号比方说我们刚才看到这个地方那么它有输入的地方 然后完了以后还有输出 输出给下一个神经元对吧好然后第二个是连接那么这个连接的目标就是为了就这边的这条线对吧为了这条线进而让两个神经元之间产生一个这个这样一条路径对吧进而实现值得传递这个连接大家不用想象不要去把它抽象化了这个连接具象化来说就是比方说你这你一个函数有一个参数那我这边调你的函数传一个参数时参和行参之间那就是一种连接你不要把它想象的特别复杂这玩意听起来都挺抽象这个神经元那一听那特别牛了人脑才有神经元的AI无分神经网络都只是为了什么去模仿他而已模仿的像不像模仿的其实不像这个计算机能做的事情大脑能做的事大脑自己大科学家都没研究明白我们怎么能说我们就模拟了大脑了只不过我们模拟了什么脑里边大量的神经元然后每一个神经元做的事情其实蛮简单的对吧那你大概这样去理解然后权重片子这个都有概念了另外这边有个叫激活函数的激活函数用来干嘛呢激活函数其实就是当我这个神经元的权重对吧或者说参数对这个神经元的权重我输入到下一个神经元的时候当然他这个神经元呢是不是会输入给你看这边按照这条鞋子我这个东西我把它称之为全连接那么每一个神经元都跟其他神经元有联系那这个神经元的输出是不是就作为下一个神经元的输入对吧那么由于这边全连接所以这五个点和这六个点之间一共有多少五六三十条连接线有三十条这么个连接线但是呢我们每如果三十条那后边一直往后如果全是全连接你想想到最后到最后它不全乱套了吗那到最后我们要分类或者预测是不是必然会有一些具体的类比那所以说为了防止这个两个点第一个我们通过激活函数呢我们可以将这个有一些这个在传递这个参数的过程当中将有一些参数呢给去掉删除了有些参数没什么用那么就不要了这个所以什么叫激活函数严格意义上来说激活函数就大概是在这个位置大概在这个位置就是上一层到下一层之间需要先经过一个激活函数那激活函数呢它的理论上的定义叫什么对神经元的输入进行非线性变化这玩意听起来是不是特别抽巧这是它原本的定义我呢给大家稍微简单的解释一下什么叫对神经元的输入进行非线性变化如果没有这个激活函数比方说我中间这个地方上一个神经元的输出做一下一个神经元的输入这边呢这个书的值我可能就需要稍微的做一些调整做一些调整要不然整个这个神经网络当中的这些参数都是线性变化的那么它就降低了很多模型理合的这个泛化能力因为它过于简单了其实每一层都比较简单的东西所以呢它需要想办法做一些变化那这个变化呢我们就通过激活函数中间插这么一角来给把上一边的一些参数给它做一些转化那转化了以后有些参数的值可能就不需要了就用不上了有些参数就没了这样呢有些参数的继续保持原样的有些参数就没了然后呢这每一次这个每一层的这个运算呢甚至有些参数你看你有什么激活函数你不同的激活函数得到值是不一样的那有些参数可能就为零那你就丢掉就丢弃掉就行了对吧您这个参数已经没有任何意义了有些参数正数有些参数是负数所以呢我们呢进入神经网络在神经元传递的一层一层传递的这个过程当中每一层我们中间都需要一个激活函数都需要一个激活函数那么当然有固定的常用的几种激活函数激活函数比较简单的只会大家理解其作用就是插在两层神经网络之间让上一层的输出的输出是不是一堆参数那到下一层呢我是有所取舍这样呢才不至于导致这个神经网络全是这种线性变化什么叫线性变化要么这一条直线嘛要么这些参数一直增加一直减少或者导致', '<h2>神经网络基础概述</h2>\n<p>本节课程主要讲解了神经网络的基本构成和核心概念，包括神经元、连接、权重以及激活函数的作用。</p>\n\n<h3>1. 神经元</h3>\n<p>神经元是神经网络的核心组成部分，负责接收输入信号并产生输出信号。每个神经元有输入端和输出端，输出可以传递给下一个神经元。</p>\n\n<h3>2. 连接</h3>\n<p>神经元之间的连接是通过路径实现的，类似于函数调用时参数的传递。这种连接不需要过于抽象化理解，其本质是为了实现信息的传递。</p>\n\n<h3>3. 权重与激活函数</h3>\n<ul>\n    <li><strong>权重：</strong>权重是神经元之间传递信号时的重要参数，决定了输入对输出的影响程度。</li>\n    <li><strong>激活函数：</strong>激活函数用于在神经元之间传递信号时进行非线性变换。它的作用是避免神经网络仅进行线性变化，从而提升模型的泛化能力。</li>\n</ul>\n\n<h3>4. 全连接层</h3>\n<p>在全连接层中，每个神经元都与下一层的所有神经元相连。例如，如果有5个神经元连接到6个神经元，则会有30条连接线。然而，全连接可能导致参数过多，因此需要通过激活函数筛选掉一些无用的参数。</p>\n\n<h3>5. 激活函数的作用</h3>\n<ul>\n    <li>对输入信号进行非线性变换。</li>\n    <li>筛选掉不重要的参数，减少冗余。</li>\n    <li>不同的激活函数会导致不同的参数值，可能为零或正负数。</li>\n</ul>\n\n<h3>总结</h3>\n<p>神经网络通过神经元、连接、权重和激活函数等基本元素构建。激活函数是非线性变换的关键，能够有效提升模型的表达能力和泛化能力，同时避免网络陷入简单的线性变化。</p>', '神经网络', '[{\'link\': \'https://baike.baidu.com/item/%E4%BA%BA%E5%B7%A5%E7%A5%9E%E7%BB%8F%E7%BD%91%E7%BB%9C/382460\', \'title\': \'人工神经网络适用于模式分类领域的技术\', \'content\': \'人工神经网络适用于模式分类领域的技术\\n人工神经网络（Artificial Neural Network，即ANN ），是20世纪80 年代以来人工智能领域兴起的研究热点。它从信息处理角度对人脑神经元网络进行抽象， 建立某种简单模型，按不同的连接方式组成不同的网络。在工程与学术界也常直接简称为神经网络或类神经网络。神经网络是一种运算模型，由大量的节点（或称神经元）之间相互联接构成。每个节点代表一种特定的输出函数，称为激励函数（activation function）。每两个节点间的连接都代表一个对于通过该连接信号的加权值，称之为权重，这相当于人工神经网络的记忆。网络的输出则依网络的连接方式，权重值和激励函数的不同而不同。而网络自身通常都是对自然界某种算法或者函数的逼近，也可能是对一种逻辑策略的表达。最近十多年来，人工神经网络的研究工作不断深入，已经取得了很大的进展，其在模式识别、智能机器人、自动控制、预测估计、生物、医学、经济等领域已成功地解决了许多现代计算机难以解决的实际问题，表现出了良好的智能特性。\', \'snippet\': \'人工神经网络（Artificial Neural Network，即ANN ），是20世纪80 年代以来人工智能领域兴起的研究热点。它从信息处理角度对人脑神经元网络进行抽象， 建立某种简单模型，按不同的连接方式组成不同的网络。在工程与学术界也常直接简称为神经网络或类神经网络。神经网络是一种运算模型，由大量的节点（或称神经元）之间相互联接构成。每个节点代表一种特定的输出函数，称为激励函数（activation function）。每两个节点间的连接都代表一个对于通过该连接信号的加权值，称之为权重，这相当于人工神经网络的记忆。网络的输出则依网络的连接方式，权重值和激励函数的不同而不同。而网络自身通常都是对自然界某种算法或者函数的逼近，也可能是对一种逻辑策略的表达。最近十多年来，人工神经网络的研究工作不断深入，已经取得了很大的进展，其在模式识别、智能机器人、自动控制、预测估计、生物、医学、经济等领域已成功地解决了许多现代计算机难以解决的实际问题，表现出了良好的智能特性。\', \'position\': None}, {\'link\': \'https://baike.baidu.com/item/%E7%A5%9E%E7%BB%8F%E7%BD%91%E7%BB%9C%E9%A2%84%E6%B5%8B%E6%8E%A7%E5%88%B6/21378306\', \'title\': \'神经网络预测控制将神经网络与预测控制相结合\', \'content\': \'神经网络预测控制将神经网络与预测控制相结合\\n神经网络预测控制，（Neural NetworkPredictive Control），人脑是一个高度复杂的、非线性的并行信息处理系统，模仿人脑的工作机理建立起来的人工神经网络具备较强的非线性输入输出映射能力。如果将人工神经网络应用于预测控制，即形成神经网络预测控制(Neural Network Predictive Control)，简称NNPC。神经网络在处理非线性问题方面有着别的方法无法比拟的优势，而预测控制对于具有约束的卡边操作问题具有非常好的针对性，因此将神经网络与预测控制相结合，发挥各自的优势，对非线性、时变、强约束、大滞后工业过程的控制提供了一个很好的解决方法。\', \'snippet\': \'神经网络预测控制，（Neural NetworkPredictive Control），人脑是一个高度复杂的、非线性的并行信息处理系统，模仿人脑的工作机理建立起来的人工神经网络具备较强的非线性输入输出映射能力。如果将人工神经网络应用于预测控制，即形成神经网络预测控制(Neural Network Predictive Control)，简称NNPC。神经网络在处理非线性问题方面有着别的方法无法比拟的优势，而预测控制对于具有约束的卡边操作问题具有非常好的针对性，因此将神经网络与预测控制相结合，发挥各自的优势，对非线性、时变、强约束、大滞后工业过程的控制提供了一个很好的解决方法。\', \'position\': None}, {\'link\': \'https://m.ibm.com/cn-zh/topics/neural-networks?\', \'title\': \'什么是神经网络？\', \'content\': \'什么是神经网络？\\n每个节点都与其他节点相连，具有一个关联的权重和阈值。神经网络依靠训练数据来学习并随着时间的推移提高其准确性。一旦对其准确性进行微调，它们就会成为计算机科学和人工智能领域的强大工具，可高速进行数据分类和聚类。神经网络有时被称为人工神经网络 (ANN) 或模拟神经网络 (SNN)。\', \'snippet\': \'每个节点都与其他节点相连，具有一个关联的权重和阈值。神经网络依靠训练数据来学习并随着时间的推移提高其准确性。一旦对其准确性进行微调，它们就会成为计算机科学和人工智能领域的强大工具，可高速进行数据分类和聚类。神经网络有时被称为人工神经网络 (ANN) 或模拟神经网络 (SNN)。\', \'position\': None}, {\'link\': \'https://developer.aliyun.com/article/1629362\', \'title\': \'神经网络有哪些应用场景呢\', \'content\': \'神经网络有哪些应用场景呢\\n以下是一些主要的应用场景： 一、图像与视频处理图像识别 ：包括人脸识别、物体识别、图像分类等。例如，在人脸识别领域，神经网络可以通过分析人脸的特征，实现高效的身份认证和识别。 目标检测 ：在图像或视频中检测并定位感...\', \'snippet\': \'以下是一些主要的应用场景： 一、图像与视频处理图像识别 ：包括人脸识别、物体识别、图像分类等。例如，在人脸识别领域，神经网络可以通过分析人脸的特征，实现高效的身份认证和识别。 目标检测 ：在图像或视频中检测并定位感...\', \'position\': None}]', '{\'meta\': {\'name\': \'神经网络\', \'author\': \'AI生成\', \'version\': \'1.0\'}, \'format\': \'node_tree\', \'data\': {\'id\': \'1\', \'topic\': \'神经网络的核心概念\', \'children\': [{\'id\': \'1-1\', \'topic\': \'神经元\', \'children\': [{\'id\': \'1-1-1\', \'topic\': \'功能：接收输入信号并产生输出信号\', \'children\': []}, {\'id\': \'1-1-2\', \'topic\': \'结构：输入 -> 处理 -> 输出至下一个神经元\', \'children\': []}]}, {\'id\': \'1-2\', \'topic\': \'连接\', \'children\': [{\'id\': \'1-2-1\', \'topic\': \'定义：实现神经元之间的路径传递\', \'children\': []}, {\'id\': \'1-2-2\', \'topic\': \'具象化：函数调用时参数传递的机制\', \'children\': []}]}, {\'id\': \'1-3\', \'topic\': \'权重\', \'children\': [{\'id\': \'1-3-1\', \'topic\': \'作用：影响神经元输入与输出的关系\', \'children\': []}]}, {\'id\': \'1-4\', \'topic\': \'激活函数\', \'children\': [{\'id\': \'1-4-1\', \'topic\': \'定义：对神经元输入进行非线性变化\', \'children\': []}, {\'id\': \'1-4-2\', \'topic\': \'作用：筛选重要参数，提升模型泛化能力\', \'children\': []}, {\'id\': \'1-4-3\', \'topic\': \'常用激活函数：如ReLU、Sigmoid、Tanh等\', \'children\': []}]}, {\'id\': \'1-5\', \'topic\': \'全连接层\', \'children\': [{\'id\': \'1-5-1\', \'topic\': \'定义：每个神经元与下一层所有神经元相连\', \'children\': []}, {\'id\': \'1-5-2\', \'topic\': \'问题：连接数过多可能导致复杂度增加\', \'children\': []}, {\'id\': \'1-5-3\', \'topic\': \'解决方法：通过激活函数减少无效参数\', \'children\': []}]}]}}', '\n{\n    \"choices\": [\n        {\n            \"question\": \"神经网络中最核心的组成部分是什么？\",\n            \"options\": {\n                \"A\": \"激活函数\",\n                \"B\": \"神经元\",\n                \"C\": \"权重\",\n                \"D\": \"连接线\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"在神经网络中，连接的作用是什么？\",\n            \"options\": {\n                \"A\": \"传递信号\",\n                \"B\": \"存储数据\",\n                \"C\": \"定义模型结构\",\n                \"D\": \"调整参数\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"激活函数的主要作用是什么？\",\n            \"options\": {\n                \"A\": \"增加模型的非线性能力\",\n                \"B\": \"减少模型参数\",\n                \"C\": \"加速训练过程\",\n                \"D\": \"优化网络结构\"\n            },\n            \"answer\": \"A\"\n        },\n        {\n            \"question\": \"全连接层的特点是什么？\",\n            \"options\": {\n                \"A\": \"每个神经元只与部分神经元相连\",\n                \"B\": \"每个神经元都与其他神经元相连\",\n                \"C\": \"只有输入层和输出层相连\",\n                \"D\": \"只有隐藏层之间相连\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"以下哪种情况会导致神经网络模型的泛化能力降低？\",\n            \"options\": {\n                \"A\": \"使用了过多的激活函数\",\n                \"B\": \"网络层数过深\",\n                \"C\": \"参数全部为线性变化\",\n                \"D\": \"输入数据过于复杂\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"激活函数如何帮助神经网络进行参数取舍？\",\n            \"options\": {\n                \"A\": \"通过将所有参数设置为零\",\n                \"B\": \"通过将部分参数值变为零或无效\",\n                \"C\": \"通过增加更多的神经元\",\n                \"D\": \"通过减少网络层数\"\n            },\n            \"answer\": \"B\"\n        },\n        {\n            \"question\": \"以下哪一项不是激活函数的作用？\",\n            \"options\": {\n                \"A\": \"引入非线性变化\",\n                \"B\": \"过滤无用参数\",\n                \"C\": \"直接优化权重值\",\n                \"D\": \"控制参数传播\"\n            },\n            \"answer\": \"C\"\n        },\n        {\n            \"question\": \"为什么神经网络需要模仿人脑神经元？\",\n            \"options\": {\n                \"A\": \"为了完全复制人脑功能\",\n                \"B\": \"为了提高计算效率\",\n                \"C\": \"为了实现更复杂的任务处理\",\n                \"D\": \"为了简化模型结构\"\n            },\n            \"answer\": \"C\"\n        }\n    ],\n    \"qas\": [\n        {\n            \"question\": \"请解释什么是全连接层，并举例说明其工作原理。\",\n            \"answer\": \"全连接层是指神经网络中每一层的神经元都与下一层的所有神经元相连。例如，如果有5个神经元连接到下一层的6个神经元，则会有30条连接线。这些连接线上的权重决定了信息传递的方式。\"\n        },\n        {\n            \"question\": \"激活函数在神经网络中的具体作用是什么？请结合实际应用场景说明。\",\n            \"answer\": \"激活函数用于对神经元的输入进行非线性变化，从而增强模型的表达能力和泛化能力。例如，在图像分类任务中，激活函数可以过滤掉无关特征，突出关键信息，帮助模型更好地识别目标。\"\n        },\n        {\n            \"question\": \"为什么神经网络需要避免参数的线性变化？请结合理论和实际应用进行分析。\",\n            \"answer\": \"如果参数仅发生线性变化，神经网络的每一层相当于只是简单地叠加线性变换，最终模型等价于单层线性模型，无法处理复杂的非线性问题。例如，在语音识别任务中，线性模型难以捕捉音频信号中的复杂模式，而引入非线性激活函数后，模型性能显著提升。\"\n        }\n    ]\n}\n', '2025-06-08 23:59:23');
